// AE's applyPreset can manage its own undo state for .ffx files; wrapping it in
// beginUndoGroup/endUndoGroup can trigger "Undo group mismatch" warnings.
toolkit.applyCustomPreset = function(p) {
    var comp = this.getComp();
    if (!comp || comp.selectedLayers.length === 0) {
        return "error::Please select at least one layer.";
    }
    try {
        var f = new File(p);
        if (!f.exists) return "error::Preset file not found.";

        comp.selectedLayers[0].applyPreset(f);
        return "success::Preset applied.";
    } catch (err) {
        return "error::Preset apply failed: " + err.toString();
    }
};

toolkit.importSfxAsset = function(filePath) {
    var comp = this.getComp ? this.getComp() : (app.project && app.project.activeItem);
    if (!(comp instanceof CompItem)) return "error::Please open a composition first.";
    if (!app.project) return "error::Project is not ready.";

    var file = new File(filePath);
    if (!file.exists) return "error::SFX file was not found.";

    app.beginUndoGroup("Import SFX");
    try {
        var item = null;
        for (var i = 1; i <= app.project.numItems; i++) {
            var existing = app.project.item(i);
            try {
                if (existing && existing.file && existing.file.fsName === file.fsName) {
                    item = existing;
                    break;
                }
            } catch (existingErr) {}
        }

        if (!item) {
            var importOptions = new ImportOptions(file);
            item = app.project.importFile(importOptions);
        }
        if (!item) return "error::SFX import failed.";

        var layer = comp.layers.add(item);
        layer.startTime = comp.time;
        layer.inPoint = comp.time;
        try {
            var duration = item.duration || layer.source.duration || 0;
            var outPoint = Math.min(comp.duration, comp.time + duration);
            if (duration > 0 && outPoint > layer.inPoint) layer.outPoint = outPoint;
        } catch (durationErr) {}
        try { layer.name = "SFX - " + item.name; } catch (nameErr) {}
        return "success::SFX added to timeline.";
    } catch (err) {
        return "error::SFX import failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

