toolkit.importPastedImage = function(filePath) {
    var comp = this.getComp ? this.getComp() : (app.project && app.project.activeItem);
    if (!(comp instanceof CompItem)) return "error::Please open a composition first.";
    if (!app.project) return "error::Project is not ready.";

    var file = new File(filePath);
    if (!file.exists) return "error::Image file was not found.";

    app.beginUndoGroup("Import Image");
    try {
        var importOptions = new ImportOptions(file);
        var item = app.project.importFile(importOptions);
        if (!item) return "error::Image import failed.";

        var layer = comp.layers.add(item);
        layer.startTime = comp.time;
        layer.inPoint = comp.time;
        try {
            var duration = item.duration || 0;
            if (duration && duration > 0) layer.outPoint = Math.min(comp.duration, comp.time + duration);
            else layer.outPoint = Math.min(comp.duration, comp.time + 5);
        } catch (durationErr) {}
        try { layer.name = "IMG - " + item.name; } catch (nameErr) {}
        try {
            var width = item.width || layer.width || 0;
            var height = item.height || layer.height || 0;
            if (width && height) {
                var fit = Math.min((comp.width * 0.82) / width, (comp.height * 0.82) / height, 1);
                layer.transform.scale.setValue([fit * 100, fit * 100]);
            }
            layer.transform.position.setValue([comp.width / 2, comp.height / 2]);
        } catch (fitErr) {}
        return "success::Image imported.";
    } catch (err) {
        return "error::Image import failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

// Shared with createAdjustmentLayer: comp.layers.addSolid(rgb, name, comp.width, comp.height, 1)
toolkit.addCompSolidLayer = function(comp, rgb, name) {
    return comp.layers.addSolid(rgb, name, comp.width, comp.height, 1);
};

// Override: comp-sized solid; picker color; batch-create above every selected layer.
toolkit.createColoredSolid = function(hex) {
    var comp = this.getComp();
    if (!comp) return;
    app.beginUndoGroup("Create Solid");
    try {
        hex = String(hex || "").replace(/^#/, "");
        if (hex.length === 3) {
            hex = hex.charAt(0) + hex.charAt(0) + hex.charAt(1) + hex.charAt(1) + hex.charAt(2) + hex.charAt(2);
        }
        if (hex.length < 6) hex = (hex + "000000").substring(0, 6);
        var rgb = [
            parseInt(hex.substring(0, 2), 16) / 255,
            parseInt(hex.substring(2, 4), 16) / 255,
            parseInt(hex.substring(4, 6), 16) / 255
        ];
        if (isNaN(rgb[0]) || isNaN(rgb[1]) || isNaN(rgb[2])) rgb = [1, 0, 0];

        var selected = this.getSelectedLayersForBatchCreation(comp);
        if (selected.length > 0) {
            selected.sort(function(a, b) { return b.index - a.index; });
            for (var i = 0; i < selected.length; i++) {
                var target = selected[i];
                var layer = this.addCompSolidLayer(comp, rgb, "Solid");
                try { layer.adjustmentLayer = false; } catch (solidTypeErr) {}
                layer.inPoint = target.inPoint;
                layer.outPoint = target.outPoint;
                this.placeCreatedLayerAboveTarget(layer, target);
            }
        } else {
            var span = this.getLen(comp);
            var layer = this.addCompSolidLayer(comp, rgb, "Solid");
            try { layer.adjustmentLayer = false; } catch (solidNoSelectionErr) {}
            layer.inPoint = span.i;
            layer.outPoint = span.o;
            try { layer.moveToBeginning(); } catch (topErr) {}
        }
    } finally {
        app.endUndoGroup();
    }
};

// ==========================================
// COMP SAVER EXTENDSCRIPT EXTENSIONS
// ==========================================

toolkit.saveComposition = function(storagePath, compId) {
    var comp = app.project.activeItem;
    if (!comp || !(comp instanceof CompItem)) {
        return "error::Please select or open a composition first.";
    }

    var compName = comp.name;
    var duration = comp.duration;
    var width = comp.width;
    var height = comp.height;
    var frameRate = comp.frameRate;

    // Determine target preview duration (exactly 5s minimum/maximum)
    var previewDuration = Math.max(duration, 5.0);
    if (duration > 5.0) {
        previewDuration = 5.0;
    }

    // Create persistent directory for this saved composition
    var compFolder = new Folder(storagePath + "/" + compId);
    if (!compFolder.exists) {
        compFolder.create();
    }

    // Backup current project state
    var originalFile = app.project.file;
    var isUntitled = false;
    var backupFile = null;
    var origRes = comp.resolutionFactor;
    var resultString = "";
    var hasMp4 = false;

    // Set resolution to 1/4 to render fast previews
    try { comp.resolutionFactor = [4, 4]; } catch(e) {}

    // Create a temporary preview composition to loop if original is short
    var tempComp = null;
    var renderSource = comp;

    try {
        if (duration < 5.0) {
            var loops = Math.ceil(5.0 / duration);
            var tempCompDuration = loops * duration;
            tempComp = app.project.items.addComp("kwv_temp_preview_comp", width, height, comp.pixelAspect, tempCompDuration, frameRate);
            tempComp.resolutionFactor = [4, 4];
            
            // Loop original composition by adding it multiple times as layers
            for (var k = 0; k < loops; k++) {
                var layer = tempComp.layers.add(comp);
                layer.startTime = k * duration;
            }
            renderSource = tempComp;
        }

        // Order 1: Try to render MP4 preview
        var mp4File = new File(compFolder.fsName + "/preview.mp4");
        try {
            var rqItem = app.project.renderQueue.items.add(renderSource);
            var om = rqItem.outputModule(1);
            om.file = mp4File;
            om.applyTemplate("H.264");
            
            // Render exactly the first 5 seconds
            rqItem.timeSpanStart = 0;
            rqItem.timeSpanDuration = previewDuration;
            
            app.project.renderQueue.render();
            
            if (mp4File.exists && mp4File.length > 0) {
                hasMp4 = true;
            }
        } catch(renderErr) {
            hasMp4 = false;
        } finally {
            // Remove item from render queue
            try {
                if (app.project.renderQueue.numItems > 0) {
                    app.project.renderQueue.item(app.project.renderQueue.numItems).remove();
                }
            } catch(e) {}
        }

        var totalFrames = 0;
        if (!hasMp4) {
            // Order 2: Fallback to PNG image sequence (max 60 frames spread across previewDuration)
            var maxFrames = 60;
            totalFrames = Math.round(previewDuration * frameRate);
            if (totalFrames > maxFrames) {
                totalFrames = maxFrames;
            }
            if (totalFrames < 1) totalFrames = 1;

            var framesFolder = new Folder(compFolder.fsName + "/frames");
            if (!framesFolder.exists) {
                framesFolder.create();
            }

            for (var i = 0; i < totalFrames; i++) {
                var time = (totalFrames > 1) ? (i / (totalFrames - 1)) * (previewDuration - 0.01) : 0;
                var frameFile = new File(framesFolder.fsName + "/frame_" + i + ".png");
                renderSource.saveFrameToPng(time, frameFile);
            }
        }

        // Restore resolution
        try { comp.resolutionFactor = origRes; } catch(e) {}

        // Delete temporary preview composition before saving project copy
        if (tempComp) {
            try { tempComp.remove(); } catch(e) {}
            tempComp = null;
        }

        // Save composition project copy
        if (!originalFile) {
            isUntitled = true;
            backupFile = new File(Folder.temp.fsName + "/untitled_backup.aep");
            app.project.save(backupFile);
            originalFile = backupFile;
        } else {
            app.project.save();
        }

        var tempProjectFile = new File(compFolder.fsName + "/comp.aep");
        app.project.save(tempProjectFile);

        var targetComp = null;
        for (var j = 1; j <= app.project.numItems; j++) {
            var item = app.project.item(j);
            if (item && item instanceof CompItem && item.name === compName) {
                targetComp = item;
                break;
            }
        }

        if (targetComp) {
            app.project.reduceProject([targetComp]);

            // Create assets folder
            var assetsFolder = new Folder(compFolder.fsName + "/assets");
            if (!assetsFolder.exists) {
                assetsFolder.create();
            }

            var depList = [];

            // Remap and copy all dependencies remaining in the project
            for (var m = 1; m <= app.project.numItems; m++) {
                var prjItem = app.project.item(m);
                if (prjItem && prjItem instanceof FootageItem && prjItem.mainSource && prjItem.mainSource.file) {
                    var origAssetFile = prjItem.mainSource.file;
                    if (origAssetFile && origAssetFile.exists) {
                        var assetExt = origAssetFile.name.split('.').pop().toLowerCase();
                        var assetSubdir = "other";
                        if (assetExt === "png" || assetExt === "jpg" || assetExt === "jpeg" || assetExt === "psd" || assetExt === "tiff" || assetExt === "tga" || assetExt === "gif") {
                            assetSubdir = "images";
                        } else if (assetExt === "mov" || assetExt === "mp4" || assetExt === "avi" || assetExt === "mkv" || assetExt === "m4v") {
                            assetSubdir = "videos";
                        } else if (assetExt === "mp3" || assetExt === "wav" || assetExt === "aac" || assetExt === "m4a" || assetExt === "aif" || assetExt === "aiff") {
                            assetSubdir = "audio";
                        } else if (assetExt === "ai" || assetExt === "eps" || assetExt === "pdf") {
                            assetSubdir = "vectors";
                        }

                        var targetSubdir = new Folder(assetsFolder.fsName + "/" + assetSubdir);
                        if (!targetSubdir.exists) {
                            targetSubdir.create();
                        }

                        var destAssetFile = new File(targetSubdir.fsName + "/" + origAssetFile.name);

                        try {
                            origAssetFile.copy(destAssetFile);
                            if (destAssetFile.exists) {
                                prjItem.replace(destAssetFile);
                                depList.push({
                                    name: prjItem.name,
                                    type: "Footage",
                                    originalPath: origAssetFile.fsName,
                                    localPath: destAssetFile.fsName
                                });
                            }
                        } catch(copyErr) {
                            // Fallback if copy fails, keep original reference
                        }
                    }
                }
            }

            // Save dependencies.json
            var depFile = new File(compFolder.fsName + "/dependencies.json");
            try {
                depFile.open("w");
                depFile.write(JSON.stringify(depList));
                depFile.close();
            } catch(e) {}

            app.project.save();
        }

        var metadata = {
            id: compId,
            name: compName,
            width: width,
            height: height,
            duration: previewDuration,
            frameRate: frameRate,
            totalFrames: totalFrames,
            hasMp4: hasMp4
        };

        resultString = "success::" + JSON.stringify(metadata);

    } catch (e) {
        try { comp.resolutionFactor = origRes; } catch(err) {}
        try { if (tempComp) tempComp.remove(); } catch(err) {}
        resultString = "error::Could not save composition: " + e.toString();
    } finally {
        // Reopen original project to restore workspace
        try {
            if (originalFile && originalFile.exists) {
                app.open(originalFile);
            }
        } catch(openErr) {}
    }

    return resultString;
};

toolkit.importSavedComposition = function(aepPath) {
    if (!app.project) return "error::No active project found.";
    var file = new File(aepPath);
    if (!file.exists) return "error::Saved composition file was not found.";

    var resultString = "";
    try {
        // Importing an .aep/.aepx project manages its own undo transaction in AE.
        // Wrapping it can trigger "Undo group mismatch" warnings after import.
        var importOptions = new ImportOptions(file);
        var importedItem = app.project.importFile(importOptions);
        if (importedItem && importedItem instanceof FolderItem) {
            for (var i = 1; i <= importedItem.numItems; i++) {
                var child = importedItem.item(i);
                if (child && child instanceof CompItem) {
                    child.openInViewer();
                    break;
                }
            }
        }
        resultString = "success::Imported composition successfully.";
    } catch (e) {
        resultString = "error::Could not import composition: " + e.toString();
    }
    return resultString;
};

toolkit.kwvGetAeMajorVersion = function() {
    try {
        var major = parseInt(String(app.version || "").split(".")[0], 10);
        if (isNaN(major)) return "error::Could not detect After Effects version.";
        return "success::" + major;
    } catch (e) {
        return "error::Could not detect After Effects version: " + e.toString();
    }
};

toolkit.kwvSaveOpenProjectToLibrary = function() {
    if (!app.project) return "error::No active project found.";
    if (!app.project.file) return "error::Save this AE project once, then add it to the library.";

    try {
        app.project.save();
        var path = app.project.file.fsName;
        var name = app.project.file.name;
        return "success::" + JSON.stringify({ path: path, name: name });
    } catch (e) {
        return "error::Could not save current AE project: " + e.toString();
    }
};

