// DEEPGRAM AUTO CAPTION ENHANCEMENTS
// ==========================================

toolkit.kwvAutoCaptionRgb = function(hex) {
    hex = String(hex || "#FFFFFF").replace(/^#/, "");
    if (hex.length === 3) hex = hex.charAt(0)+hex.charAt(0)+hex.charAt(1)+hex.charAt(1)+hex.charAt(2)+hex.charAt(2);
    var r = parseInt(hex.substring(0,2),16), g = parseInt(hex.substring(2,4),16), b = parseInt(hex.substring(4,6),16);
    if (isNaN(r) || isNaN(g) || isNaN(b)) return [1,1,1];
    return [r/255,g/255,b/255];
};

toolkit.kwvCleanCaptionWord = function(word) {
    var text = String(word == null ? "" : word).replace(/^\s+|\s+$/g, "");
    text = text.replace(/^[\.,;:!?'"()\[\]{}]+|[\.,;:!?'"()\[\]{}]+$/g, "");
    if (/^[\.,;:!?'"()\[\]{}-]+$/.test(text)) return "";
    return text;
};
toolkit.kwvRomanizeHindiText = function(text) {
    var s = String(text == null ? "" : text);
    var cons = {"क":"k","ख":"kh","ग":"g","घ":"gh","ङ":"ng","च":"ch","छ":"chh","ज":"j","झ":"jh","ञ":"ny","ट":"t","ठ":"th","ड":"d","ढ":"dh","ण":"n","त":"t","थ":"th","द":"d","ध":"dh","न":"n","प":"p","फ":"f","ब":"b","भ":"bh","म":"m","य":"y","र":"r","ल":"l","व":"v","श":"sh","ष":"sh","स":"s","ह":"h","ळ":"l"};
    var matra = {"ा":"a","ि":"i","ी":"ee","ु":"u","ू":"oo","े":"e","ै":"ai","ो":"o","ौ":"au","ृ":"ri"};
    var vowel = {"अ":"a","आ":"aa","इ":"i","ई":"ee","उ":"u","ऊ":"oo","ए":"e","ऐ":"ai","ओ":"o","औ":"au"};
    var out = "";
    for (var i = 0; i < s.length; i++) {
        var ch = s.charAt(i);
        if (cons[ch]) {
            var next = s.charAt(i + 1);
            out += cons[ch];
            if (next === "्") { i++; continue; }
            if (matra[next]) { out += matra[next]; i++; continue; }
            out += "a";
            continue;
        }
        if (vowel[ch]) { out += vowel[ch]; continue; }
        if (ch === "ं" || ch === "ँ") { out += "n"; continue; }
        if (ch === "ः") { out += "h"; continue; }
        if (matra[ch] || ch === "्") continue;
        out += ch;
    }
    out = out.replace(/a(\s|$)/g, "$1");
    return out.replace(/\s+/g, " ").replace(/^\s+|\s+$/g, "");
};

toolkit.kwvNormalizeHinglishWord = function(word) {
    var text = String(word == null ? "" : word);
    var key = text.toLowerCase();
    var map = {
        "nahin": "nahi",
        "rabin": "raveen",
        "vaale": "wale",
        "achchhi": "acchi",
        "chizen": "cheezein",
        "chizen.": "cheezein",
        "ajib": "ajeeb",
        "mainne": "maine",
        "dekhate": "dekhte",
        "samaajh": "samajh",
        "samjhega": "samjhega",
        "saalon": "saalo",
        "bhaai": "bhai",
        "halo": "hello",
        "yah": "ye",
        "paega": "paega"
    };
    return map[key] || text;
};

toolkit.kwvPushHinglishWord = function(out, source, text, start, end) {
    if (!text) return;
    out.push({
        start: start,
        end: end,
        word: this.kwvNormalizeHinglishWord(text)
    });
};

toolkit.kwvApplyHinglishPhraseFixes = function(words) {
    var out = [];
    function lowerAt(index) {
        return words[index] ? String(words[index].word || "").toLowerCase() : "";
    }
    function emitSplit(startIndex, endIndex, parts) {
        var start = words[startIndex].start;
        var end = words[endIndex].end;
        var span = Math.max(0.03, (end - start) / parts.length);
        for (var p = 0; p < parts.length; p++) {
            this.kwvPushHinglishWord(out, words[startIndex], parts[p], start + (span * p), p === parts.length - 1 ? end : start + (span * (p + 1)));
        }
    }
    for (var i = 0; i < words.length; i++) {
        if (lowerAt(i) === "mark" && lowerAt(i + 1) === "ka" && lowerAt(i + 2) === "samay" && lowerAt(i + 3) === "to" && lowerAt(i + 4) === "main") {
            emitSplit.call(this, i, i + 4, ["maa", "kasam", "main"]);
            i += 4;
            continue;
        }
        if (lowerAt(i) === "kisi" && lowerAt(i + 1) === "ka" && lowerAt(i + 2) === "baat") {
            emitSplit.call(this, i, i + 2, ["kisi", "ka", "baap"]);
            i += 2;
            continue;
        }
        if (lowerAt(i) === "samajh" && lowerAt(i + 1) === "hai" && lowerAt(i + 2) === "khelne") {
            emitSplit.call(this, i, i + 2, ["samajh", "gaye", "khelne"]);
            i += 2;
            continue;
        }
        if (lowerAt(i) === "guest" && lowerAt(i + 1) === "believe") {
            this.kwvPushHinglishWord(out, words[i], "guys", words[i].start, words[i].end);
            continue;
        }
        this.kwvPushHinglishWord(out, words[i], words[i].word, words[i].start, words[i].end);
    }
    return out;
};

toolkit.kwvAutoCaptionOptions = function(raw) {
    var opt = {};
    try {
        if (raw && String(raw).charAt(0) === "{") opt = JSON.parse(String(raw));
        else opt.maxChars = parseInt(raw, 10);
    } catch (e) { opt = {}; }
    var maxChars = parseInt(opt.maxChars, 10);
    if (isNaN(maxChars) || maxChars < 8) maxChars = 42;
    return {
        maxChars: maxChars,
        wordsPerCaption: parseInt(opt.wordsPerCaption, 10) || 4,
        language: String(opt.language || ""),
        mode: String(opt.mode || "phrase"),
        scope: String(opt.scope || "selected"),
        fontSize: parseInt(opt.fontSize, 10) || 60,
        position: String(opt.position || "bottom"),
        textColor: String(opt.textColor || "#FFFFFF"),
        animation: String(opt.animation || "pop")
    };
};

toolkit.callAutoCaptionDeepgram = function(wav, apiKey) {
    var tmp = wav.parent.fsName;
    var id = Math.random().toString(36).slice(2);
    var jsonFile = new File(tmp + "/kv_resp_" + id + ".json");
    try {
        if (jsonFile.exists) jsonFile.remove();
        var wavPath = wav.fsName;
        var jsonPath = jsonFile.fsName;
        if ($.os.indexOf("Windows") !== -1) {
            wavPath = wavPath.replace(/\\/g, "/");
            jsonPath = jsonPath.replace(/\\/g, "/");
        }
        var lang = this.autoCaptionTrim(this.getAutoCaptionSetting("language", ""));
        if (lang === "hinglish") lang = "hi-Latn";
        var url = "https://api.deepgram.com/v1/listen?model=nova-2&smart_format=true&punctuate=true&diarize=false&filler_words=false";
        if (lang) url += "&language=" + encodeURIComponent(lang);
        var cmd = "curl -sS --max-time 120 --connect-timeout 15 -X POST " + this.autoCaptionEscapeShell(url) + " -H " + this.autoCaptionEscapeShell("Authorization: Token " + apiKey) + " -H " + this.autoCaptionEscapeShell("Content-Type: audio/wav") + " --data-binary " + this.autoCaptionEscapeShell("@" + wavPath) + " -o " + this.autoCaptionEscapeShell(jsonPath);
        system.callSystem(cmd);
        if (!jsonFile.exists) throw new Error("No response from Deepgram.");
        jsonFile.encoding = "UTF-8";
        if (!jsonFile.open("r")) throw new Error("Deepgram response could not be opened.");
        var response = jsonFile.read();
        jsonFile.close();
        if (this.autoCaptionTrim(response) === "") throw new Error("Empty response from Deepgram.");
        var parsed = JSON.parse(response);
        if (!parsed || !parsed.results) throw new Error("Unexpected response from Deepgram.");
        return parsed;
    } finally {
        try { if (wav && wav.exists) wav.remove(); } catch (wavRemoveErr) {}
        try { if (jsonFile && jsonFile.exists) jsonFile.remove(); } catch (jsonRemoveErr) {}
    }
};

toolkit.groupAutoCaptionWordsWithMode = function(words, options, timeOffset) {
    var clean = [];
    for (var i = 0; i < words.length; i++) {
        var text = this.kwvCleanCaptionWord(words[i].word);
        if (options.language === "hinglish" && /[\u0900-\u097F]/.test(text)) text = this.kwvRomanizeHindiText(text);
        if (options.language === "hinglish") text = this.kwvNormalizeHinglishWord(text);
        if (!text) continue;
        clean.push({ start: words[i].start, end: words[i].end, word: text });
    }
    if (options.language === "hinglish") clean = this.kwvApplyHinglishPhraseFixes(clean);
    if (options.mode === "word") {
        var wordGroups = [];
        for (var w = 0; w < clean.length; w++) wordGroups.push({ inPoint: timeOffset + clean[w].start, outPoint: timeOffset + clean[w].end + 0.08, text: clean[w].word });
        return wordGroups;
    }
    if (options.mode === "phrase" && options.wordsPerCaption) {
        var phraseGroups = [];
        var step = parseInt(options.wordsPerCaption, 10);
        if (isNaN(step) || step < 2) step = 4;
        for (var q = 0; q < clean.length; q += step) {
            var chunk = clean.slice(q, q + step);
            var parts2 = [];
            for (var c = 0; c < chunk.length; c++) parts2.push(chunk[c].word);
            phraseGroups.push({ inPoint: timeOffset + chunk[0].start, outPoint: timeOffset + chunk[chunk.length - 1].end + 0.08, text: parts2.join(" ") });
        }
        return phraseGroups;
    }
    return this.groupAutoCaptionWords(clean, options.maxChars, timeOffset);
};

toolkit.normalizeAutoCaptionGroups = function(groups) {
    if (!groups || !groups.length) return groups || [];
    groups.sort(function(a, b) { return (a.inPoint || 0) - (b.inPoint || 0); });
    for (var i = 0; i < groups.length; i++) {
        var cur = groups[i];
        var next = groups[i + 1];
        if (!cur) continue;
        cur.inPoint = Math.max(0, parseFloat(cur.inPoint) || 0);
        cur.outPoint = Math.max(cur.inPoint + 0.12, parseFloat(cur.outPoint) || (cur.inPoint + 0.5));
        if (next) {
            var nextIn = Math.max(0, parseFloat(next.inPoint) || 0);
            if (cur.outPoint > nextIn) cur.outPoint = Math.max(cur.inPoint + 0.08, nextIn);
        }
    }
    return groups;
};

toolkit._kwvAutoCaptionCancelRequested = function(cancelPath) {
    if (!cancelPath) return false;
    try {
        var f = new File(String(cancelPath));
        return f.exists;
    } catch (err) {
        return false;
    }
};

toolkit._kwvRemoveCreatedCaptionLayers = function(layers) {
    if (!layers || !layers.length) return;
    for (var i = layers.length - 1; i >= 0; i--) {
        try {
            if (layers[i]) layers[i].remove();
        } catch (err) {}
    }
};

toolkit.markSubtitleLayer = function(layer, text, startTime) {
    if (!layer) return;
    try {
        layer.name = this._kwvCaptionCleanLayerName ? this._kwvCaptionCleanLayerName("KWV_SUBTITLE", text || "Caption") : ("KWV_SUBTITLE_" + Math.round((startTime || 0) * 1000));
    } catch (nameErr) {}
    try {
        var token = "KWV_AUTO_CAPTION";
        var meta = "text=" + String(text || "").replace(/\r|\n/g, " ") + "|time=" + String(startTime || 0);
        layer.comment = token + "\n" + meta;
    } catch (commentErr) {}
};

toolkit._kwvIsSubtitleLayer = function(layer) {
    if (!layer) return false;
    var name = "";
    var comment = "";
    try { name = String(layer.name || ""); } catch (nameErr) {}
    try { comment = String(layer.comment || ""); } catch (commentErr) {}
    if (comment.indexOf("KWV_AUTO_CAPTION") >= 0) return true;
    if (comment.indexOf("KWV_AUTO_CAPTION_RUN:") >= 0) return true;
    if (/^(KWV_SUBTITLE|CAP_UPPER|CAP_HIGHLIGHT|CAP_LOWER)_/i.test(name)) return true;
    if (/^Subtitle\s+/i.test(name) || /^Caption\s+/i.test(name)) return true;
    return false;
};

toolkit.deleteSubtitleLayers = function() {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var removed = 0;
    app.beginUndoGroup("Delete KWV Subtitles");
    try {
        for (var i = comp.numLayers; i >= 1; i--) {
            var layer = comp.layer(i);
            if (this._kwvIsSubtitleLayer(layer)) {
                layer.remove();
                removed++;
            }
        }
    } catch (err) {
        try { app.endUndoGroup(); } catch (undoErr) {}
        return "error::Delete subtitles failed: " + err.toString();
    }
    app.endUndoGroup();
    return "success::Removed " + removed + " subtitle layer(s).";
};

toolkit._kwvMarkCaptionRun = function(layer, runId) {
    if (!layer || !runId) return;
    try {
        var token = "KWV_AUTO_CAPTION_RUN:" + String(runId);
        var oldComment = String(layer.comment || "");
        if (oldComment.indexOf(token) < 0) layer.comment = oldComment ? oldComment + "\n" + token : token;
    } catch (err) {}
};

toolkit._kwvDeleteCaptionRun = function(comp, runId) {
    if (!comp || !runId) return 0;
    var token = "KWV_AUTO_CAPTION_RUN:" + String(runId);
    var removed = 0;
    for (var i = comp.numLayers; i >= 1; i--) {
        try {
            var layer = comp.layer(i);
            if (layer && String(layer.comment || "").indexOf(token) >= 0) {
                layer.remove();
                removed++;
            }
        } catch (err) {}
    }
    return removed;
};

toolkit.createAutoCaptionLayers = function(comp, groups, cancelPath, runId) {
    if (!comp || !groups || !groups.length) return 0;
    var fontSize = parseInt(this.getAutoCaptionSetting("fontSize", "60"), 10);
    if (isNaN(fontSize) || fontSize < 8) fontSize = 60;
    var pos = this.getAutoCaptionSetting("position", "bottom");
    var y = pos === "top" ? comp.height * 0.14 : (pos === "center" ? comp.height * 0.5 : comp.height * 0.85);
    var fill = this.kwvAutoCaptionRgb(this.getAutoCaptionSetting("textColor", "#FFFFFF"));
    var animation = String(this.getAutoCaptionSetting("animation", "pop") || "pop");
    app.beginUndoGroup("Generate Auto Captions");
    try {
        var created = 0;
        var createdLayers = [];
        for (var i = 0; i < groups.length; i++) {
            if (this._kwvAutoCaptionCancelRequested(cancelPath)) {
                this._kwvRemoveCreatedCaptionLayers(createdLayers);
                return -1;
            }
            var group = groups[i];
            if (!group || !group.text) continue;
            if (animation === "wordfade" || animation === "wordfadeinout") {
                var words = String(group.text || "").replace(/^\s+|\s+$/g, "").split(/\s+/);
                var span = Math.max(0.08, (group.outPoint - group.inPoint) / Math.max(1, words.length));
                for (var wi = 0; wi < words.length; wi++) {
                    if (!words[wi]) continue;
                    var wordIn = group.inPoint + (span * wi);
                    var wordOut = animation === "wordfadeinout" ? Math.min(group.outPoint, wordIn + Math.max(0.18, span * 1.35)) : group.outPoint;
                    var wordLayer = comp.layers.addText(words[wi]);
                    createdLayers.push(wordLayer);
                    this.markSubtitleLayer(wordLayer, words[wi], wordIn);
                    this._kwvMarkCaptionRun(wordLayer, runId);
                    wordLayer.inPoint = wordIn;
                    wordLayer.outPoint = Math.max(wordIn + 0.12, wordOut);
                    try {
                        var wordSrc = wordLayer.property("ADBE Text Properties").property("ADBE Text Document");
                        var wordDoc = wordSrc.value;
                        wordDoc.fontSize = fontSize;
                        wordDoc.justification = ParagraphJustification.CENTER_JUSTIFY;
                        wordDoc.applyFill = true;
                        wordDoc.fillColor = fill;
                        wordDoc.applyStroke = false;
                        wordDoc.strokeWidth = 0;
                        wordSrc.setValue(wordDoc);
                    } catch (wordDocErr) {}
                    try {
                        var wordRect = wordLayer.sourceRectAtTime(wordIn, false);
                        wordLayer.transform.anchorPoint.setValue([wordRect.left + (wordRect.width / 2), wordRect.top + (wordRect.height / 2)]);
                    } catch (wordRectErr) {}
                    wordLayer.transform.position.setValue([comp.width / 2, y]);
                    this._applyCaptionAnimation(wordLayer, wordIn, wordLayer.outPoint, animation === "wordfadeinout" ? "fadeinout" : "fade");
                    try { wordLayer.moveToBeginning(); } catch (wordMoveErr) {}
                    created++;
                }
                continue;
            }
            var layer = comp.layers.addText(group.text);
            createdLayers.push(layer);
            this.markSubtitleLayer(layer, group.text, group.inPoint);
            this._kwvMarkCaptionRun(layer, runId);
            layer.inPoint = group.inPoint;
            layer.outPoint = group.outPoint;
            try {
                var srcProp = layer.property("ADBE Text Properties").property("ADBE Text Document");
                var doc = srcProp.value;
                doc.fontSize = fontSize;
                doc.justification = ParagraphJustification.CENTER_JUSTIFY;
                doc.applyFill = true;
                doc.fillColor = fill;
                doc.applyStroke = false;
                doc.strokeWidth = 0;
                srcProp.setValue(doc);
            } catch (docErr) {}
            var rect = layer.sourceRectAtTime(group.inPoint, false);
            layer.transform.anchorPoint.setValue([rect.left + (rect.width / 2), rect.top + (rect.height / 2)]);
            layer.transform.position.setValue([comp.width / 2, y]);
            this._applyCaptionAnimation(layer, group.inPoint, group.outPoint, animation);
            try { layer.moveToBeginning(); } catch (moveErr) {}
            created++;
        }
        return created;
    } finally {
        app.endUndoGroup();
    }
};

toolkit.prepareAutoCaptions = function(rawOptions) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var options = this.kwvAutoCaptionOptions(rawOptions);
    var apiKey = this.autoCaptionTrim(this.getAutoCaptionSetting("apiKey", ""));
    if (!apiKey) return "error::Set the API key first.";
    this.saveAutoCaptionSetting("maxChars", options.maxChars);
    this.saveAutoCaptionSetting("language", options.language);
    this.saveAutoCaptionSetting("fontSize", options.fontSize);
    this.saveAutoCaptionSetting("position", options.position);
    this.saveAutoCaptionSetting("textColor", options.textColor);
    this.saveAutoCaptionSetting("animation", options.animation);

    var selected = comp.selectedLayers || [];
    var targetLayers = [];
    if (options.scope === "full") {
        for (var i = 1; i <= comp.numLayers; i++) {
            var layer = comp.layer(i);
            try {
                if (layer && layer.source && layer.source.file && layer.hasAudio !== false && layer.audioEnabled !== false) targetLayers.push(layer);
            } catch (layerErr) {}
        }
    } else {
        for (var s = 0; s < selected.length; s++) targetLayers.push(selected[s]);
    }
    if (!targetLayers.length) return "error::Select an audio or video layer.";

    try {
        var range = this.getAutoCaptionTimeRange(comp, targetLayers);
        var wav = this.exportAutoCaptionWav(comp, targetLayers, range);
        var raw = this.callAutoCaptionDeepgram(wav, apiKey);
        var data = this.extractAutoCaptionWords(raw);
        if ((!data.words || data.words.length === 0) && this.autoCaptionTrim(data.text) === "") return "error::No words detected.";
        if (!data.words || data.words.length === 0) {
            var text = this.kwvCleanCaptionWord(data.text);
            if (!text) return "error::No usable words detected.";
            return "success::" + JSON.stringify({ captions: [{ inPoint: range.minIn, outPoint: range.maxOut, text: text }] });
        }
        var groups = this.groupAutoCaptionWordsWithMode(data.words, options, range.minIn);
        groups = this.normalizeAutoCaptionGroups(groups);
        return "success::" + JSON.stringify({ captions: groups });
    } catch (err) {
        return "error::Auto caption failed: " + err.toString();
    }
};

toolkit._kwvCaptionStyleMode = function(style) {
    if (!style || !style.mode) return "normal";
    var mode = String(style.mode || "normal");
    if (mode === "realEstate" || mode === "multiLayer") return mode;
    return "normal";
};

toolkit._kwvCaptionCleanLayerName = function(prefix, text) {
    var clean = String(text || "").replace(/^\s+|\s+$/g, "").replace(/[\\\/:\*\?"<>\|]/g, "").replace(/\s+/g, "_");
    if (!clean) clean = "Caption";
    if (clean.length > 28) clean = clean.substring(0, 28);
    return prefix + "_" + clean;
};

toolkit._kwvCaptionDefaultPart = function(kind) {
    var appleUi = ["SegoeUI", "Segoe UI", "HelveticaNeue", "Helvetica Neue", "Arial"];
    var appleMedium = ["SegoeUI-Semibold", "Segoe UI Semibold", "SegoeUI-Bold", "Segoe UI Bold", "Arial-BoldMT", "Arial Bold", "Arial"];
    var appleHeavy = ["SegoeUI-Bold", "Segoe UI Bold", "Arial-BoldMT", "Arial Bold", "HelveticaNeue-Bold", "Helvetica Neue Bold", "Arial"];
    if (kind === "upper") return { enabled: true, font: "SegoeUI", fontCandidates: appleUi, fontSize: 36, textColor: "#FFFFFF", strokeColor: "#000000", strokeWidth: 0, shadow: true, glow: false, animation: "fade", y: -54, tracking: -6 };
    if (kind === "highlight") return { enabled: true, font: "SegoeUI-Bold", fontCandidates: appleHeavy, fontSize: 66, textColor: "#D9B45A", strokeColor: "#000000", strokeWidth: 0, shadow: true, glow: false, animation: "pop", y: 0, tracking: -12 };
    return { enabled: true, font: "SegoeUI-Semibold", fontCandidates: appleMedium, fontSize: 58, textColor: "#FFFFFF", strokeColor: "#000000", strokeWidth: 0, shadow: true, glow: false, animation: "slide", y: 54, tracking: -10 };
};

toolkit._kwvCaptionMergePart = function(input, kind) {
    var out = this._kwvCaptionDefaultPart(kind);
    if (!input) return out;
    for (var key in input) {
        try {
            if (input.hasOwnProperty(key)) out[key] = input[key];
        } catch (e) {}
    }
    return out;
};

toolkit._kwvApplyCaptionFontCandidates = function(doc, layerStyle) {
    if (!doc || !layerStyle) return "";
    var candidates = [];
    if (layerStyle.fontCandidates && layerStyle.fontCandidates.length) {
        candidates = layerStyle.fontCandidates;
    } else if (layerStyle.font) {
        candidates = [layerStyle.font];
    }
    candidates.push("Arial-BoldMT");
    candidates.push("Arial");
    for (var i = 0; i < candidates.length; i++) {
        var candidate = String(candidates[i] || "");
        if (!candidate) continue;
        try {
            doc.font = candidate;
            if (candidate.indexOf("/") < 0 && candidate.charAt(0) !== "[") {
                return candidate;
            }
            if (String(doc.font) === candidate || String(doc.font).toLowerCase().indexOf(candidate.toLowerCase()) !== -1) {
                return candidate;
            }
        } catch (fontErr) {}
    }
    return String(doc.font || "");
};

toolkit._pickHighlightWord = function(words) {
    var premium = {
        "luxury": true, "home": true, "property": true, "sale": true, "rent": true, "location": true, "price": true, "dream": true,
        "apartment": true, "villa": true, "house": true, "real": true, "estate": true, "offer": true, "premium": true,
        "beautiful": true, "modern": true, "clean": true, "interior": true, "exterior": true, "kitchen": true, "bedroom": true,
        "balcony": true, "view": true, "investment": true, "deal": true, "space": true, "elegant": true
    };
    var filler = {
        "a": true, "an": true, "the": true, "is": true, "are": true, "am": true, "i": true, "you": true, "he": true, "she": true,
        "it": true, "we": true, "they": true, "to": true, "of": true, "for": true, "in": true, "on": true, "at": true,
        "and": true, "or": true, "but": true, "with": true, "about": true
    };
    var i;
    for (i = 0; i < words.length; i++) {
        var key = String(words[i] || "").toLowerCase().replace(/^[^a-z0-9]+|[^a-z0-9]+$/g, "");
        if (premium[key] && !filler[key]) return i;
    }
    var mid = Math.floor(words.length / 2);
    var midKey = String(words[mid] || "").toLowerCase().replace(/^[^a-z0-9]+|[^a-z0-9]+$/g, "");
    if (!filler[midKey]) return mid;
    for (i = 0; i < words.length; i++) {
        var safeKey = String(words[i] || "").toLowerCase().replace(/^[^a-z0-9]+|[^a-z0-9]+$/g, "");
        if (!filler[safeKey]) return i;
    }
    return mid;
};

toolkit._splitCaptionForStyle = function(text, style) {
    var raw = String(text || "").replace(/^\s+|\s+$/g, "");
    var words = raw ? raw.split(/\s+/) : [];
    if (words.length <= 1) return { upper: "", highlight: words.length ? words[0] : "", lower: "" };
    if (words.length === 2) return { upper: words[0], highlight: words[1], lower: "" };
    var idx = this._pickHighlightWord(words);
    if (idx < 0) idx = Math.floor(words.length / 2);
    var upper = [];
    var lower = [];
    for (var i = 0; i < words.length; i++) {
        if (i < idx) upper.push(words[i]);
        else if (i > idx) lower.push(words[i]);
    }
    return { upper: upper.join(" "), highlight: words[idx] || "", lower: lower.join(" ") };
};

toolkit._getLayoutPositions = function(comp, layout, fontSizes) {
    var baseY = comp.height * 0.58;
    var gap = Math.max(42, Math.min(95, (fontSizes.highlight || 64) * 0.82));
    var name = String(layout || "stackedAnchor");
    if (name === "random") {
        var pool = ["stackedAnchor", "splitEmphasis", "compactCenter", "balancedLayout", "centerBigWord", "cleanRealEstate"];
        name = pool[Math.floor(Math.random() * pool.length)];
    }
    if (name === "wideTopInline") return { x: comp.width / 2, upperY: comp.height * 0.24, highlightY: baseY - 8, lowerY: baseY + gap };
    if (name === "splitEmphasis") return { x: comp.width / 2, upperY: baseY - gap, highlightY: baseY, lowerY: baseY + gap };
    if (name === "overlapBridge") return { x: comp.width / 2, upperY: baseY - gap * 0.65, highlightY: baseY - 6, lowerY: baseY + gap * 0.65 };
    if (name === "compactCenter") return { x: comp.width / 2, upperY: baseY - gap * 0.45, highlightY: baseY, lowerY: baseY + gap * 0.45 };
    if (name === "centerBigWord") return { x: comp.width / 2, upperY: baseY - gap * 0.9, highlightY: baseY, lowerY: baseY + gap * 0.9 };
    if (name === "topSmallBottomBig") return { x: comp.width / 2, upperY: comp.height * 0.25, highlightY: comp.height * 0.52, lowerY: comp.height * 0.72 };
    if (name === "cleanRealEstate") return { x: comp.width / 2, upperY: baseY - gap * 0.85, highlightY: baseY - 2, lowerY: baseY + gap * 0.82 };
    if (name === "editorialOffset") {
        var tightGap = Math.max(48, Math.min(86, (fontSizes.highlight || 96) * 0.46));
        return { x: comp.width / 2, upperX: comp.width * 0.41, highlightX: comp.width * 0.59, lowerX: comp.width / 2, upperY: baseY - tightGap * 0.68, highlightY: baseY - 2, lowerY: baseY + tightGap * 0.68 };
    }
    return { x: comp.width / 2, upperY: baseY - gap, highlightY: baseY, lowerY: baseY + gap };
};

toolkit._applyTextStrokeShadowGlow = function(textLayer, layerStyle) {
    if (!textLayer || !layerStyle) return;
    try {
        if (layerStyle.shadow) {
            var shadow = textLayer.property("ADBE Effect Parade").addProperty("ADBE Drop Shadow");
            if (shadow) {
                try { shadow.property("Opacity").setValue(36); } catch (s1) {}
                try { shadow.property("Direction").setValue(135); } catch (s2) {}
                try { shadow.property("Distance").setValue(4); } catch (s3) {}
                try { shadow.property("Softness").setValue(14); } catch (s4) {}
            }
        }
        if (layerStyle.glow) {
            var glow = textLayer.property("ADBE Effect Parade").addProperty("ADBE Glow");
            if (glow) {
                try { glow.property("ADBE Glow-0003").setValue(24); } catch (g1) {}
                try { glow.property("ADBE Glow-0004").setValue(18); } catch (g2) {}
            }
        }
    } catch (fxErr) {}
};

toolkit._applyCaptionAnimation = function(textLayer, tIn, tOut, animation) {
    if (!textLayer) return;
    var anim = String(animation || "none");
    if (anim === "word" || anim === "wordfade" || anim === "wordfadeinout" || anim === "wordappear") anim = anim === "wordfade" ? "fade" : (anim === "wordfadeinout" ? "fadeinout" : "slide");
    if (anim === "none") return;
    var dur = Math.min(0.22, Math.max(0.08, (tOut - tIn) * 0.25));
    try {
        var opacity = textLayer.transform.opacity;
        var pos = textLayer.transform.position;
        var scale = textLayer.transform.scale;
        if (anim === "fade" || anim === "blur" || anim === "wipe") {
            opacity.setValueAtTime(tIn, 0);
            opacity.setValueAtTime(tIn + dur, 100);
        } else if (anim === "fadeinout") {
            opacity.setValueAtTime(tIn, 0);
            opacity.setValueAtTime(tIn + dur, 100);
            opacity.setValueAtTime(Math.max(tIn + dur, tOut - dur), 100);
            opacity.setValueAtTime(tOut, 0);
        } else if (anim === "pop") {
            opacity.setValueAtTime(tIn, 0);
            opacity.setValueAtTime(tIn + dur, 100);
            scale.setValueAtTime(tIn, [82, 82]);
            scale.setValueAtTime(tIn + dur, [100, 100]);
        } else if (anim === "slide" || anim === "slidedown") {
            var p = pos.value;
            var offset = anim === "slidedown" ? -42 : 42;
            opacity.setValueAtTime(tIn, 0);
            opacity.setValueAtTime(tIn + dur, 100);
            pos.setValueAtTime(tIn, [p[0], p[1] + offset]);
            pos.setValueAtTime(tIn + dur, [p[0], p[1]]);
        }
    } catch (animErr) {}
};

toolkit._createStyledCaptionTextLayer = function(comp, text, tIn, tOut, layerStyle, xPos, yPos, layerName) {
    if (!comp || !text || !layerStyle || layerStyle.enabled === false) return null;
    var layer = comp.layers.addText(text);
    layer.name = layerName || "CAPTION_STYLE";
    layer.inPoint = tIn;
    layer.outPoint = tOut;
    try {
        var srcProp = layer.property("ADBE Text Properties").property("ADBE Text Document");
        var doc = srcProp.value;
        doc.fontSize = parseInt(layerStyle.fontSize, 10) || 60;
        doc.justification = ParagraphJustification.CENTER_JUSTIFY;
        doc.applyFill = true;
        doc.fillColor = this.kwvAutoCaptionRgb(layerStyle.textColor || "#FFFFFF");
        doc.applyStroke = false;
        doc.strokeColor = this.kwvAutoCaptionRgb(layerStyle.strokeColor || "#000000");
        doc.strokeWidth = 0;
        try { doc.tracking = parseInt(layerStyle.tracking, 10) || 0; } catch (trackErr) {}
        this._kwvApplyCaptionFontCandidates(doc, layerStyle);
        srcProp.setValue(doc);
    } catch (docErr) {}
    try {
        var rect = layer.sourceRectAtTime(tIn, false);
        layer.transform.anchorPoint.setValue([rect.left + (rect.width / 2), rect.top + (rect.height / 2)]);
        var yOffset = parseFloat(layerStyle.y) || 0;
        layer.transform.position.setValue([xPos, yPos + yOffset]);
    } catch (rectErr) {
        try { layer.transform.position.setValue([xPos, yPos]); } catch (posErr) {}
    }
    this._applyTextStrokeShadowGlow(layer, layerStyle);
    this._applyCaptionAnimation(layer, tIn, tOut, layerStyle.animation || "none");
    try { layer.moveToBeginning(); } catch (moveErr) {}
    return layer;
};

toolkit._placeMultiLayerCaptionsAE = function(comp, data) {
    var captions = data.captions || [];
    var style = data.style || {};
    var cancelPath = data.cancelPath || "";
    var runId = data.runId || "";
    if (!comp || !captions.length) return 0;
    style.upper = this._kwvCaptionMergePart(style.upper, "upper");
    style.highlight = this._kwvCaptionMergePart(style.highlight, "highlight");
    style.lower = this._kwvCaptionMergePart(style.lower, "lower");
    app.beginUndoGroup("Generate Styled Auto Captions");
    try {
        var created = 0;
        var createdLayers = [];
        for (var i = 0; i < captions.length; i++) {
            if (this._kwvAutoCaptionCancelRequested(cancelPath)) {
                this._kwvRemoveCreatedCaptionLayers(createdLayers);
                return -1;
            }
            var cap = captions[i];
            if (!cap || !cap.text) continue;
            var tIn = parseFloat(cap.inPoint);
            if (isNaN(tIn)) tIn = parseFloat(cap.startTime);
            if (isNaN(tIn)) tIn = 0;
            var tOut = parseFloat(cap.outPoint);
            if (isNaN(tOut)) tOut = parseFloat(cap.endTime);
            if (isNaN(tOut) || tOut <= tIn) tOut = tIn + 0.5;
            var split = this._splitCaptionForStyle(cap.text, style);
            var sizes = {
                upper: parseInt(style.upper && style.upper.fontSize, 10) || 46,
                highlight: parseInt(style.highlight && style.highlight.fontSize, 10) || 64,
                lower: parseInt(style.lower && style.lower.fontSize, 10) || 72
            };
            var pos = this._getLayoutPositions(comp, style.layout || "stackedAnchor", sizes);
            if (split.upper && style.upper && style.upper.enabled !== false) {
                var upperLayer = this._createStyledCaptionTextLayer(comp, split.upper, tIn, tOut, style.upper, pos.upperX || pos.x, pos.upperY, this._kwvCaptionCleanLayerName("CAP_UPPER", split.upper));
                if (upperLayer) {
                    this._kwvMarkCaptionRun(upperLayer, runId);
                    createdLayers.push(upperLayer);
                    created++;
                }
            }
            if (split.highlight && style.highlight && style.highlight.enabled !== false) {
                var highlightLayer = this._createStyledCaptionTextLayer(comp, split.highlight, tIn, tOut, style.highlight, pos.highlightX || pos.x, pos.highlightY, this._kwvCaptionCleanLayerName("CAP_HIGHLIGHT", split.highlight));
                if (highlightLayer) {
                    this._kwvMarkCaptionRun(highlightLayer, runId);
                    createdLayers.push(highlightLayer);
                    created++;
                }
            }
            if (split.lower && style.lower && style.lower.enabled !== false) {
                var lowerLayer = this._createStyledCaptionTextLayer(comp, split.lower, tIn, tOut, style.lower, pos.lowerX || pos.x, pos.lowerY, this._kwvCaptionCleanLayerName("CAP_LOWER", split.lower));
                if (lowerLayer) {
                    this._kwvMarkCaptionRun(lowerLayer, runId);
                    createdLayers.push(lowerLayer);
                    created++;
                }
            }
        }
        return created;
    } finally {
        app.endUndoGroup();
    }
};

toolkit.createAutoCaptionLayersFromFile = function(filePath) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    try {
        var f = new File(filePath);
        if (!f.exists) return "error::Caption data file not found.";
        f.encoding = "UTF-8";
        if (!f.open("r")) return "error::Could not open caption data.";
        var raw = f.read();
        f.close();
        var data = JSON.parse(raw);
        var options = data.options || {};
        this.saveAutoCaptionSetting("fontSize", options.fontSize || 60);
        this.saveAutoCaptionSetting("position", options.position || "bottom");
        this.saveAutoCaptionSetting("textColor", options.textColor || "#FFFFFF");
        this.saveAutoCaptionSetting("animation", options.animation || "pop");
        var created = this._kwvCaptionStyleMode(data.style) === "normal" ? this.createAutoCaptionLayers(comp, data.captions || [], data.cancelPath || "", data.runId || "") : this._placeMultiLayerCaptionsAE(comp, data);
        if (created < 0) return "cancelled::Auto caption add cancelled.";
        return "success::Added " + created + " caption layer(s) to comp.";
    } catch (err) {
        return "error::Add to Comp failed: " + err.toString();
    }
};

toolkit.createAutoCaptionLayersFromJson = function(rawJson) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    try {
        var data = JSON.parse(String(rawJson || "{}"));
        var options = data.options || {};
        this.saveAutoCaptionSetting("fontSize", options.fontSize || 60);
        this.saveAutoCaptionSetting("position", options.position || "bottom");
        this.saveAutoCaptionSetting("textColor", options.textColor || "#FFFFFF");
        this.saveAutoCaptionSetting("animation", options.animation || "pop");
        var created = this._kwvCaptionStyleMode(data.style) === "normal" ? this.createAutoCaptionLayers(comp, data.captions || [], data.cancelPath || "", data.runId || "") : this._placeMultiLayerCaptionsAE(comp, data);
        if (created < 0) return "cancelled::Auto caption add cancelled.";
        return "success::Added " + created + " caption layer(s) to comp.";
    } catch (err) {
        return "error::Add to Comp failed: " + err.toString();
    }
};

toolkit.createAutoCaptionLayersFromFileBatch = function(filePath, startIndex, batchSize) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    try {
        var f = new File(filePath);
        if (!f.exists) return "error::Caption data file not found.";
        f.encoding = "UTF-8";
        if (!f.open("r")) return "error::Could not open caption data.";
        var raw = f.read();
        f.close();
        var data = JSON.parse(raw);
        var options = data.options || {};
        var allCaptions = data.captions || [];
        var start = parseInt(startIndex, 10);
        var size = parseInt(batchSize, 10);
        if (isNaN(start) || start < 0) start = 0;
        if (isNaN(size) || size < 1) size = 1;
        if (this._kwvAutoCaptionCancelRequested(data.cancelPath || "")) {
            this._kwvDeleteCaptionRun(comp, data.runId || "");
            return "cancelled::Auto caption add cancelled.";
        }
        this.saveAutoCaptionSetting("fontSize", options.fontSize || 60);
        this.saveAutoCaptionSetting("position", options.position || "bottom");
        this.saveAutoCaptionSetting("textColor", options.textColor || "#FFFFFF");
        this.saveAutoCaptionSetting("animation", options.animation || "pop");
        var slice = [];
        var end = Math.min(allCaptions.length, start + size);
        for (var i = start; i < end; i++) slice.push(allCaptions[i]);
        data.captions = slice;
        var created = this._kwvCaptionStyleMode(data.style) === "normal" ? this.createAutoCaptionLayers(comp, slice, data.cancelPath || "", data.runId || "") : this._placeMultiLayerCaptionsAE(comp, data);
        if (created < 0) {
            this._kwvDeleteCaptionRun(comp, data.runId || "");
            return "cancelled::Auto caption add cancelled.";
        }
        return "success::" + JSON.stringify({ created: created, nextIndex: end, total: allCaptions.length, done: end >= allCaptions.length });
    } catch (err) {
        return "error::Add to Comp failed: " + err.toString();
    }
};

toolkit.deleteAutoCaptionRun = function(runId) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    try {
        var removed = this._kwvDeleteCaptionRun(comp, runId || "");
        return "success::Removed " + removed + " caption layer(s).";
    } catch (err) {
        return "error::Caption cleanup failed: " + err.toString();
    }
};

toolkit.saveAutoCaptionSrt = function(content) {
    try {
        var folder = Folder.selectDialog("Select folder to save SRT");
        if (!folder) return "error::SRT save cancelled.";
        if (!folder || !folder.exists) folder = Folder.myDocuments;
        var stamp = "";
        try {
            var d = new Date();
            stamp = "_" + d.getFullYear() + ("0" + (d.getMonth() + 1)).slice(-2) + ("0" + d.getDate()).slice(-2) + "_" + ("0" + d.getHours()).slice(-2) + ("0" + d.getMinutes()).slice(-2) + ("0" + d.getSeconds()).slice(-2);
        } catch (dateErr) {}
        var f = new File(folder.fsName + "/kwv-auto-captions" + stamp + ".srt");
        f.encoding = "UTF-8";
        if (!f.open("w")) return "error::Could not create SRT file.";
        f.write(String(content || ""));
        f.close();
        return "success::SRT saved: " + f.fsName;
    } catch (err) {
        return "error::SRT save failed: " + err.toString();
    }
};

toolkit.generateAutoCaptions = function(rawOptions) {
    var prepared = this.prepareAutoCaptions(rawOptions);
    if (!prepared || prepared.indexOf("error::") === 0) return prepared;
    try {
        var comp = this.getComp();
        var data = JSON.parse(prepared.substring(9));
        var created = this.createAutoCaptionLayers(comp, data.captions || []);
        return "success::Generated " + created + " subtitle layer(s).";
    } catch (err) {
        return "error::Auto caption failed: " + err.toString();
    }
};

toolkit.getSelectedMediaSourcePath = function() {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var selected = comp.selectedLayers || [];
    if (!selected.length) return "error::Select an audio or video layer.";

    for (var i = 0; i < selected.length; i++) {
        var layer = selected[i];
        try {
            if (!layer || !layer.source || !layer.source.file) continue;
            if (layer.hasAudio === false && layer.hasVideo === false) continue;
            var sourceFile = layer.source.file;
            if (!sourceFile || !sourceFile.exists) continue;
            return "success::" + JSON.stringify({
                path: sourceFile.fsName,
                layerName: layer.name,
                layerIndex: layer.index,
                inPoint: layer.inPoint,
                outPoint: layer.outPoint,
                startTime: layer.startTime
            });
        } catch (layerErr) {}
    }

    return "error::The selected layer's local source file was not found. Select a footage audio/video layer.";
};

toolkit.autoCutSelectedLayerSilence = function(rawPayload) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    try {
        var payload = JSON.parse(String(rawPayload || "{}"));
        var layerInfo = payload.layer || {};
        var silences = payload.silences || [];
        if (!silences.length) return "error::No silence ranges found.";

        var layer = null;
        try {
            if (layerInfo.index) layer = comp.layer(parseInt(layerInfo.index, 10));
        } catch (indexErr) {}
        if (!layer) {
            var selected = comp.selectedLayers || [];
            if (selected.length) layer = selected[0];
        }
        if (!layer) return "error::Select a layer.";
        if (layer.locked) return "error::Selected layer locked hai.";

        var stretch = 1;
        try {
            stretch = (layer.stretch ? layer.stretch : 100) / 100;
        } catch (stretchErr) {
            stretch = 1;
        }
        if (stretch === 0) stretch = 1;
        if (stretch < 0) return "error::Auto cut does not currently support reversed layers.";

        var visibleStart = layer.inPoint;
        var visibleEnd = layer.outPoint;
        var originalStartTime = layer.startTime;
        var frame = comp.frameDuration || (1 / Math.max(1, comp.frameRate || 30));
        var minLen = Math.max(frame, 0.02);
        var cutRanges = [];

        for (var i = 0; i < silences.length; i++) {
            var s = parseFloat(silences[i].start);
            var e = parseFloat(silences[i].end);
            if (isNaN(s) || isNaN(e) || e <= s) continue;
            var compStart = originalStartTime + (s * stretch);
            var compEnd = originalStartTime + (e * stretch);
            compStart = Math.max(visibleStart, compStart);
            compEnd = Math.min(visibleEnd, compEnd);
            if (compEnd - compStart >= minLen) cutRanges.push({ start: compStart, end: compEnd });
        }

        if (!cutRanges.length) return "error::Detected silence is not inside the selected layer's visible range.";
        cutRanges.sort(function(a, b) { return a.start - b.start; });

        var merged = [];
        for (var m = 0; m < cutRanges.length; m++) {
            var cur = cutRanges[m];
            if (!merged.length || cur.start > merged[merged.length - 1].end + minLen) {
                merged.push({ start: cur.start, end: cur.end });
            } else if (cur.end > merged[merged.length - 1].end) {
                merged[merged.length - 1].end = cur.end;
            }
        }

        var keep = [];
        var cursor = visibleStart;
        for (var r = 0; r < merged.length; r++) {
            if (merged[r].start - cursor >= minLen) keep.push({ start: cursor, end: merged[r].start });
            cursor = Math.max(cursor, merged[r].end);
        }
        if (visibleEnd - cursor >= minLen) keep.push({ start: cursor, end: visibleEnd });
        if (!keep.length) return "error::Only silence was found in the layer; the original clip was not removed.";

        app.beginUndoGroup("KWV Silence Auto Cut");
        try {
            var outputCursor = visibleStart;
            var created = [];
            for (var k = 0; k < keep.length; k++) {
                var seg = keep[k];
                var segLen = seg.end - seg.start;
                var dup = layer.duplicate();
                try { dup.name = layer.name + " cut " + (k + 1); } catch (nameErr) {}
                dup.startTime = originalStartTime + outputCursor - seg.start;
                dup.inPoint = outputCursor;
                dup.outPoint = outputCursor + segLen;
                created.push(dup);
                outputCursor += segLen;
            }
            layer.remove();
            if (created.length > 1) {
                var stackAnchor = created[created.length - 1];
                for (var o = created.length - 2; o >= 0; o--) {
                    try {
                        created[o].moveAfter(stackAnchor);
                        stackAnchor = created[o];
                    } catch (orderErr) {}
                }
            }
            for (var c = 0; c < created.length; c++) {
                try { created[c].selected = true; } catch (selectErr) {}
            }
            var removed = merged.length;
            return "success::Auto cut done: " + created.length + " clip piece(s), " + removed + " silence cut(s) removed.";
        } finally {
            app.endUndoGroup();
        }
    } catch (err) {
        return "error::Auto cut failed: " + err.toString();
    }
};

toolkit._kwvCocoHexToRgb = function(hex) {
    var clean = String(hex || "").replace(/^\s+|\s+$/g, "");
    if (clean.charAt(0) === "#") clean = clean.substring(1);
    if (clean.length === 3) clean = clean.charAt(0) + clean.charAt(0) + clean.charAt(1) + clean.charAt(1) + clean.charAt(2) + clean.charAt(2);
    if (!/^[0-9a-fA-F]{6}$/.test(clean)) return null;
    return [
        parseInt(clean.substring(0, 2), 16) / 255,
        parseInt(clean.substring(2, 4), 16) / 255,
        parseInt(clean.substring(4, 6), 16) / 255
    ];
};

toolkit._kwvCocoSetTextColor = function(layer, rgb, mode) {
    try {
        if (!(layer instanceof TextLayer)) return false;
        var sourceText = layer.property("ADBE Text Properties").property("ADBE Text Document");
        var doc = sourceText.value;
        if (mode !== "stroke") {
            doc.applyFill = true;
            doc.fillColor = rgb;
        }
        if (mode !== "fill") {
            doc.applyStroke = true;
            doc.strokeColor = rgb;
        }
        sourceText.setValue(doc);
        return true;
    } catch (err) {
        return false;
    }
};

toolkit._kwvCocoSetVectorColors = function(group, rgb, mode) {
    var changed = 0;
    if (!group || !group.numProperties) return changed;
    for (var i = 1; i <= group.numProperties; i++) {
        var prop = group.property(i);
        if (!prop) continue;
        try {
            if (mode !== "stroke" && prop.matchName === "ADBE Vector Graphic - Fill") {
                var fillColor = prop.property("ADBE Vector Fill Color");
                if (fillColor) {
                    fillColor.setValue(rgb);
                    changed++;
                }
            }
            if (mode !== "fill" && prop.matchName === "ADBE Vector Graphic - Stroke") {
                var strokeColor = prop.property("ADBE Vector Stroke Color");
                if (strokeColor) {
                    strokeColor.setValue(rgb);
                    changed++;
                }
            }
        } catch (colorErr) {}
        changed += this._kwvCocoSetVectorColors(prop, rgb, mode);
    }
    return changed;
};

toolkit._kwvCocoSetLayerColor = function(layer, rgb, mode) {
    var changed = false;
    if (!layer) return false;
    if (this._kwvCocoSetTextColor(layer, rgb, mode)) changed = true;
    try {
        var contents = layer.property("ADBE Root Vectors Group");
        if (contents && this._kwvCocoSetVectorColors(contents, rgb, mode) > 0) changed = true;
    } catch (shapeErr) {}
    try {
        if (!changed && layer.property("ADBE Effect Parade")) {
            this._kwvCocoRemoveNamedEffects(layer, ["KWV Color Fill"]);
            var fill = layer.property("ADBE Effect Parade").addProperty("ADBE Fill");
            if (fill) {
                fill.name = "KWV Color Fill";
                fill.property("ADBE Fill-0002").setValue(rgb);
                changed = true;
            }
        }
    } catch (fillErr) {}
    return changed;
};

toolkit._kwvCocoRemoveNamedEffects = function(layer, names) {
    try {
        var effects = layer.property("ADBE Effect Parade");
        if (!effects || !effects.numProperties) return;
        for (var i = effects.numProperties; i >= 1; i--) {
            var effect = effects.property(i);
            if (!effect) continue;
            for (var n = 0; n < names.length; n++) {
                if (effect.name === names[n]) {
                    effect.remove();
                    break;
                }
            }
        }
    } catch (err) {}
};

toolkit.applyCocoColor = function(hex, mode) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var rgb = this._kwvCocoHexToRgb(hex);
    if (!rgb) return "error::Invalid color code.";
    var selected = comp.selectedLayers || [];
    if (!selected.length) return "error::Please select at least one layer.";
    app.beginUndoGroup("KWV Apply Color");
    try {
        var changed = 0;
        for (var i = 0; i < selected.length; i++) {
            if (this._kwvCocoSetLayerColor(selected[i], rgb, mode || "both")) changed++;
        }
        if (!changed) return "error::No editable text, shape, or effect color found.";
        return "success::Color applied.";
    } catch (err) {
        return "error::Color apply failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

toolkit.applyCocoPalette = function(hexList, mode) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var parts = String(hexList || "").split(",");
    var colors = [];
    for (var i = 0; i < parts.length; i++) {
        var rgb = this._kwvCocoHexToRgb(parts[i]);
        if (rgb) colors.push(rgb);
    }
    if (!colors.length) return "error::No valid palette colors found.";
    var selected = comp.selectedLayers || [];
    if (!selected.length) return "error::Please select at least one layer.";
    app.beginUndoGroup("KWV Apply Palette");
    try {
        var changed = 0;
        for (var j = 0; j < selected.length; j++) {
            if (this._kwvCocoSetLayerColor(selected[j], colors[j % colors.length], mode || "both")) changed++;
        }
        if (!changed) return "error::No editable text, shape, or effect color found.";
        return "success::Palette applied.";
    } catch (err) {
        return "error::Palette apply failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

toolkit.applyCocoGradient = function(type, angle, hexList, mode, encodedSteps) {
    var comp = this.getComp();
    if (!comp) return "error::Please select a composition.";
    var parts = String(hexList || "").split(",");
    var first = this._kwvCocoHexToRgb(parts[0]);
    var last = this._kwvCocoHexToRgb(parts.length > 1 ? parts[parts.length - 1] : parts[0]);
    if (!first) return "error::No valid gradient colors found.";
    if (!last) last = first;
    var selected = comp.selectedLayers || [];
    if (!selected.length) return "error::Please select at least one layer.";
    app.beginUndoGroup("KWV Apply Gradient");
    try {
        var changed = 0;
        for (var i = 0; i < selected.length; i++) {
            var layer = selected[i];
            if (this._kwvCocoSetLayerColor(layer, first, mode || "both")) changed++;
            try {
                var effects = layer.property("ADBE Effect Parade");
                if (effects) {
                    this._kwvCocoRemoveNamedEffects(layer, ["KWV Color Fill", "KWV Gradient Ramp"]);
                    var ramp = effects.addProperty("ADBE Ramp");
                    if (ramp) {
                        ramp.name = "KWV Gradient Ramp";
                        ramp.property("ADBE Ramp-0001").setValue([0, 0]);
                        ramp.property("ADBE Ramp-0002").setValue(first);
                        ramp.property("ADBE Ramp-0003").setValue([comp.width, comp.height]);
                        ramp.property("ADBE Ramp-0004").setValue(last);
                        try { ramp.property("ADBE Ramp-0005").setValue(1); } catch (shapeErr) {}
                        try { ramp.property("ADBE Ramp-0007").setValue(0); } catch (blendErr) {}
                        changed++;
                    }
                }
            } catch (rampErr) {}
        }
        if (!changed) return "error::No editable layer found for gradient.";
        return "success::Gradient applied.";
    } catch (err) {
        return "error::Gradient apply failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

// Safer Liquid Glass wrapper: clamp generated glass size and clean up partial layers/comps on AE errors.
// This avoids memory-style failures when a selected source layer is extremely large.
toolkit.getLiquidGlassGeometry = function(comp, kind, customWidth, customHeight) {
    var position = [comp.width / 2, comp.height / 2];
    var width = 500;
    var height = 500;
    var safeKind = String(kind || "rectangle").toLowerCase();
    var maxGlassSize = 2000;
    var sel = comp.selectedLayers;

    if (sel && sel.length > 0) {
        var layer = sel[0];
        try {
            var pos = layer.property("ADBE Transform Group").property("ADBE Position").value;
            if (pos && pos.length >= 2) position = [pos[0], pos[1]];
        } catch (e1) {}
        var measured = this.getLayerMeasuredSize(layer, comp);
        width = Math.max(180, Math.round(measured.width * 1.2));
        height = Math.max(180, Math.round(measured.height * 1.2));
    }

    var forcedWidth = parseInt(customWidth, 10);
    var forcedHeight = parseInt(customHeight, 10);
    if (!isNaN(forcedWidth) && forcedWidth > 0) width = forcedWidth;
    if (!isNaN(forcedHeight) && forcedHeight > 0) height = forcedHeight;

    width = Math.min(maxGlassSize, Math.max(20, width));
    height = Math.min(maxGlassSize, Math.max(20, height));

    if (safeKind === "circle" || safeKind === "square" || safeKind === "diamond" || safeKind === "star") {
        var maxSide = Math.min(maxGlassSize, Math.max(width, height));
        width = maxSide;
        height = maxSide;
    } else if (safeKind === "oval") {
        width = Math.min(maxGlassSize, Math.max(width, Math.round(height * 1.35)));
    } else if (safeKind === "triangle" || safeKind === "cone") {
        height = Math.min(maxGlassSize, Math.max(height, Math.round(width * 1.18)));
    } else if (safeKind === "cylinder") {
        width = Math.min(maxGlassSize, Math.max(170, Math.round(width * 0.72)));
        height = Math.min(maxGlassSize, Math.max(260, Math.round(height * 1.35)));
    } else if (safeKind === "pentagon" || safeKind === "hexagon" || safeKind === "octagon") {
        var polySide = Math.min(maxGlassSize, Math.max(width, height));
        width = polySide;
        height = polySide;
    }

    return { position: position, width: width, height: height };
};

toolkit.createLiquidGlass = function(kind, customWidth, customHeight) {
    var activeComp = this.getComp();
    if (!(activeComp instanceof CompItem)) return "error::No active composition found.";
    if (activeComp.width > 8192 || activeComp.height > 8192 || (activeComp.width * activeComp.height) > 33554432) {
        return "error::Composition bahut large hai. Liquid Glass ke liye 8K ya smaller comp use karo.";
    }

    var keyComp = null;
    var glassLayer = null;
    var keyLayer = null;
    var adjustLayer = null;

    app.beginUndoGroup("APPLE Liquid Glass");
    try {
        var span = this.getLen(activeComp);
        var geometry = this.getLiquidGlassGeometry(activeComp, kind, customWidth, customHeight);
        var glassLayerName = this.getUniqueLayerName("LiquidGlass");
        var keyCompName = this.getUniqueCompName("LiquidGlass by keshav");
        var frameRate = activeComp.frameRate;
        var duration = activeComp.duration;
        keyComp = app.project.items.addComp(keyCompName, activeComp.width, activeComp.height, 1, duration, frameRate);

        this.addLiquidGlassShapeLayer(keyComp, kind, glassLayerName, activeComp.name);

        glassLayer = activeComp.layers.add(keyComp);
        glassLayer.name = glassLayerName;
        glassLayer.inPoint = span.i;
        glassLayer.outPoint = span.o;
        try { glassLayer.property("ADBE Transform Group").property("Position").setValue(geometry.position); } catch (e1) {}
        this.addLiquidGlassControlsToLayer(glassLayer, geometry.width, geometry.height);
        this.applyLiquidGlassLayerStyle(glassLayer, activeComp, glassLayerName, activeComp.name);
        glassLayer.label = 2;

        keyLayer = activeComp.layers.add(keyComp);
        keyLayer.name = keyCompName;
        keyLayer.inPoint = span.i;
        keyLayer.outPoint = span.o;
        try { keyLayer.property("ADBE Transform Group").property("Position").setValue(geometry.position); } catch (e2) {}
        keyLayer.parent = glassLayer;

        adjustLayer = this.addLiquidGlassAdjustmentLayerToActiveComp(activeComp, glassLayerName, activeComp.name);
        if (!adjustLayer) return "error::Adjustment layer create nahi hua.";
        adjustLayer.inPoint = span.i;
        adjustLayer.outPoint = span.o;

        try {
            adjustLayer.setTrackMatte(keyLayer, TrackMatteType.ALPHA);
        } catch (e3) {
            try { adjustLayer.trackMatteType = TrackMatteType.ALPHA; } catch (e4) {}
        }

        try { keyLayer.moveAfter(glassLayer); } catch (e5) {}
        try { adjustLayer.moveAfter(keyLayer); } catch (e6) {}

        keyLayer.enabled = false;
        keyLayer.locked = true;
        keyLayer.label = 0;
        adjustLayer.locked = true;
        adjustLayer.label = 0;

        for (var i = 1; i <= activeComp.numLayers; i++) activeComp.layer(i).selected = false;
        glassLayer.selected = true;

        return "success::Created APPLE Liquid Glass for " + String(kind || "shape") + ".";
    } catch (err) {
        try { if (adjustLayer) { adjustLayer.locked = false; adjustLayer.remove(); } } catch (cleanup1) {}
        try { if (keyLayer) { keyLayer.locked = false; keyLayer.remove(); } } catch (cleanup2) {}
        try { if (glassLayer) { glassLayer.locked = false; glassLayer.remove(); } } catch (cleanup3) {}
        try { if (keyComp) keyComp.remove(); } catch (cleanup4) {}
        return "error::Could not create Liquid Glass: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
};

toolkit.stackSelectedLayersByFrame = function(mode) {
    var comp = this.getComp();
    if (!(comp instanceof CompItem)) return "error::Open/select a composition first.";

    var layers = comp.selectedLayers;
    if (!layers || layers.length < 2) return "error::Select at least two layers.";

    var frame = comp.frameDuration;
    if (!frame || frame <= 0) frame = 1 / (comp.frameRate || 25);
    var safeMode = String(mode || "");
    var changed = 0;
    var locked = 0;
    var stackLayers = [];

    for (var s = 0; s < layers.length; s++) {
        if (!layers[s] || layers[s].locked) {
            locked++;
        } else {
            stackLayers.push(layers[s]);
        }
    }

    if (stackLayers.length < 2) return "error::Select at least two unlocked layers.";

    stackLayers.sort(function(a, b) {
        return b.index - a.index;
    });

    app.beginUndoGroup("Keshav 1 Frame Stack");
    try {
        for (var i = 0; i < stackLayers.length; i++) {
            var layer = stackLayers[i];
            var dir = 0;
            if (safeMode === "backward") {
                dir = -1;
            } else if (safeMode === "forward") {
                dir = 1;
            } else {
                return "error::Unknown frame adjustment.";
            }
            var delta = frame * i * dir;
            layer.startTime = layer.startTime + delta;
            changed++;
        }
    } catch (err) {
        return "error::Frame adjust failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }

    if (changed < 2) return "error::Select at least two unlocked layers.";
    var msg = "Stacked " + changed + " layers by 1 frame.";
    if (locked > 0) msg += " " + locked + " locked layer" + (locked === 1 ? "" : "s") + " skipped.";
    return "success::" + msg;
};

toolkit.alignSelectedLayersToPlayhead = function(edge) {
    var comp = this.getComp();
    if (!(comp instanceof CompItem)) return "error::Open/select a composition first.";

    var layers = comp.selectedLayers;
    if (!layers || layers.length < 1) return "error::Select at least one layer.";

    var safeEdge = String(edge || "");
    var targetTime = comp.time;
    var changed = 0;
    var locked = 0;

    app.beginUndoGroup("Keshav Align Layers To Playhead");
    try {
        for (var i = 0; i < layers.length; i++) {
            var layer = layers[i];
            if (!layer || layer.locked) {
                locked++;
                continue;
            }

            var startTimeOffset = layer.inPoint - layer.startTime;
            var layerSpan = layer.outPoint - layer.inPoint;
            var targetInPoint = targetTime;
            if (safeEdge === "in") {
                targetInPoint = targetTime;
            } else if (safeEdge === "out") {
                targetInPoint = targetTime - layerSpan;
            } else {
                return "error::Unknown align mode.";
            }

            layer.startTime = targetInPoint - startTimeOffset;
            changed++;
        }
    } catch (err) {
        return "error::Align failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }

    if (changed < 1) return "error::No unlocked selected layer found.";
    var msg = "Aligned " + changed + " layer" + (changed === 1 ? "" : "s") + " to playhead.";
    if (locked > 0) msg += " " + locked + " locked layer" + (locked === 1 ? "" : "s") + " skipped.";
    return "success::" + msg;
};

toolkit.purgeAfterEffectsCache = function() {
    try {
        app.purge(PurgeTarget.ALL_CACHES);
        return "success::After Effects cache purged.";
    } catch (err) {
        try {
            app.purge(PurgeTarget.UNDO_CACHES);
            app.purge(PurgeTarget.IMAGE_CACHES);
            app.purge(PurgeTarget.SNAPSHOT_CACHES);
            return "success::After Effects cache purged.";
        } catch (fallbackErr) {
            return "error::Purge failed: " + err.toString();
        }
    }
};

toolkit._kwvGetTextLayerText = function(layer) {
    try {
        if (!(layer instanceof TextLayer)) return "";
        var prop = layer.property("ADBE Text Properties").property("ADBE Text Document");
        if (!prop) return "";
        var doc = prop.value;
        return String(doc && doc.text != null ? doc.text : "");
    } catch (err) {
        return "";
    }
};

toolkit._kwvSetTextLayerText = function(layer, text) {
    try {
        var prop = layer.property("ADBE Text Properties").property("ADBE Text Document");
        var doc = prop.value;
        doc.text = String(text == null ? "" : text);
        prop.setValue(doc);
        return true;
    } catch (err) {
        return false;
    }
};

toolkit._kwvExploderTokens = function(text, mode) {
    var out = [];
    var raw = String(text || "");
    if (String(mode || "") === "chars") {
        for (var i = 0; i < raw.length; i++) {
            var ch = raw.charAt(i);
            if (!/\s/.test(ch)) out.push(ch);
        }
        return out;
    }
    var words = raw.replace(/^\s+|\s+$/g, "").split(/\s+/);
    for (var w = 0; w < words.length; w++) {
        if (words[w]) out.push(words[w]);
    }
    return out;
};

toolkit._kwvExploderParts = function(text, mode) {
    var out = [];
    var raw = String(text || "");
    if (String(mode || "") === "chars") {
        for (var i = 0; i < raw.length; i++) {
            var ch = raw.charAt(i);
            if (!/\s/.test(ch)) out.push({ text: ch, start: i, end: i + 1 });
        }
        return out;
    }
    var re = /\S+/g;
    var match;
    while ((match = re.exec(raw)) !== null) {
        out.push({ text: match[0], start: match.index, end: match.index + match[0].length });
    }
    return out;
};

toolkit._kwvSafeExplodedLayerName = function(prefix, token, index) {
    var clean = String(token || "").replace(/[\\\/:\*\?"<>\|]/g, "").replace(/\s+/g, "_");
    if (!clean) clean = "Text";
    if (clean.length > 20) clean = clean.substring(0, 20);
    return prefix + "_" + (index + 1) + "_" + clean;
};

toolkit._kwvClearExploderPropertyKeys = function(prop) {
    if (!prop) return;
    try {
        if (prop.canSetExpression && prop.expressionEnabled) prop.expressionEnabled = false;
    } catch (exprErr) {}
    try {
        while (prop.numKeys && prop.numKeys > 0) prop.removeKey(prop.numKeys);
    } catch (keyErr) {}
};

toolkit._kwvGetSeparatedPositionProp = function(transform, axis) {
    if (!transform) return null;
    var match = axis === 0 ? "ADBE Position_0" : (axis === 1 ? "ADBE Position_1" : "ADBE Position_2");
    try {
        for (var i = 1; i <= transform.numProperties; i++) {
            var prop = transform.property(i);
            if (prop && prop.matchName === match) return prop;
        }
    } catch (err) {}
    return null;
};

toolkit._kwvGetTransformPositionValue = function(transform) {
    if (!transform) return null;
    try {
        var pos = transform.property("ADBE Position");
        if (pos && pos.value && pos.value.length !== undefined) return pos.value;
    } catch (posErr) {}
    var x = null, y = null, z = null;
    try {
        var xProp = this._kwvGetSeparatedPositionProp(transform, 0);
        var yProp = this._kwvGetSeparatedPositionProp(transform, 1);
        var zProp = this._kwvGetSeparatedPositionProp(transform, 2);
        if (xProp) x = xProp.value;
        if (yProp) y = yProp.value;
        if (zProp) z = zProp.value;
    } catch (sepErr) {}
    if (x === null || y === null) return null;
    return z === null ? [x, y] : [x, y, z];
};

toolkit._kwvSetTransformPositionValue = function(transform, value) {
    if (!transform || !value) return false;
    try {
        var pos = transform.property("ADBE Position");
        if (pos) {
            try { pos.setValue(value); return true; } catch (setErr) {}
        }
    } catch (posErr) {}
    try {
        var xProp = this._kwvGetSeparatedPositionProp(transform, 0);
        var yProp = this._kwvGetSeparatedPositionProp(transform, 1);
        var zProp = this._kwvGetSeparatedPositionProp(transform, 2);
        if (xProp) xProp.setValue(value[0]);
        if (yProp) yProp.setValue(value[1]);
        if (zProp && value.length > 2) zProp.setValue(value[2]);
        return !!(xProp && yProp);
    } catch (sepErr) {}
    return false;
};

toolkit._kwvPrepareExplodedTransform = function(layer) {
    try {
        var transform = layer.property("ADBE Transform Group");
        if (!transform) return;
        this._kwvClearExploderPropertyKeys(transform.property("ADBE Position"));
        this._kwvClearExploderPropertyKeys(this._kwvGetSeparatedPositionProp(transform, 0));
        this._kwvClearExploderPropertyKeys(this._kwvGetSeparatedPositionProp(transform, 1));
        this._kwvClearExploderPropertyKeys(this._kwvGetSeparatedPositionProp(transform, 2));
        this._kwvClearExploderPropertyKeys(transform.property("ADBE Anchor Point"));
    } catch (err) {}
};

toolkit._kwvCenterExplodedTextAnchor = function(layer, timeValue) {
    if (!layer) return;
    try {
        var rect = layer.sourceRectAtTime(timeValue || 0, false);
        var transform = layer.property("ADBE Transform Group");
        var anchor = transform ? transform.property("ADBE Anchor Point") : null;
        var position = this._kwvGetTransformPositionValue(transform);
        if (!rect || !anchor) return;
        var oldAnchor = anchor.value;
        var oldPosition = position;
        var nextAnchor = [rect.left + (rect.width / 2), rect.top + (rect.height / 2)];
        anchor.setValue(nextAnchor);
        if (oldPosition) {
            var scale = [100, 100, 100];
            try { scale = transform.property("ADBE Scale").value; } catch (scaleErr) {}
            var nextPosition = [];
            for (var i = 0; i < oldPosition.length; i++) nextPosition.push(oldPosition[i]);
            nextPosition[0] += (nextAnchor[0] - oldAnchor[0]) * ((scale[0] || 100) / 100);
            nextPosition[1] += (nextAnchor[1] - oldAnchor[1]) * ((scale[1] || 100) / 100);
            this._kwvSetTransformPositionValue(transform, nextPosition);
        }
    } catch (err) {}
};

toolkit._kwvGetLayerVisualCenter = function(layer, timeValue) {
    try {
        var rect = layer.sourceRectAtTime(timeValue || 0, false);
        if (rect && layer.toComp) return layer.toComp([rect.left + (rect.width / 2), rect.top + (rect.height / 2), 0]);
    } catch (toCompErr) {}
    try {
        var transform = layer.property("ADBE Transform Group");
        var pos = transform ? transform.property("ADBE Position").value : null;
        if (pos) return pos;
    } catch (posErr) {}
    return null;
};

toolkit._kwvMeasureExploderTextWidth = function(sourceLayer, text, timeValue) {
    var temp = null;
    try {
        temp = sourceLayer.duplicate();
        this._kwvSetTextLayerText(temp, text);
        var rect = temp.sourceRectAtTime(timeValue || 0, false);
        return Math.max(0, rect ? rect.width : 0);
    } catch (err) {
        return 0;
    } finally {
        try { if (temp) temp.remove(); } catch (removeErr) {}
    }
};

toolkit._kwvMeasureExploderTextAdvance = function(sourceLayer, text, timeValue) {
    return this._kwvMeasureExploderTextWidth(sourceLayer, text, timeValue);
};

toolkit._kwvSetTextRangePercent = function(selector, startPercent, endPercent) {
    if (!selector) return;
    try {
        var start = selector.property("ADBE Text Percent Start");
        if (start) start.setValue(Math.max(0, Math.min(100, startPercent)));
    } catch (startErr) {}
    try {
        var end = selector.property("ADBE Text Percent End");
        if (end) end.setValue(Math.max(0, Math.min(100, endPercent)));
    } catch (endErr) {}
    try {
        var offset = selector.property("ADBE Text Percent Offset");
        if (offset) offset.setValue(0);
    } catch (offsetErr) {}
};

toolkit._kwvAddTextOpacityRange = function(layer, name, opacityValue, startPercent, endPercent) {
    try {
        var textProps = layer.property("ADBE Text Properties");
        var animators = textProps ? textProps.property("ADBE Text Animators") : null;
        if (!animators) return false;
        var animator = animators.addProperty("ADBE Text Animator");
        if (!animator) return false;
        try { animator.name = name; } catch (nameErr) {}
        var props = animator.property("ADBE Text Animator Properties");
        var opacity = props ? props.addProperty("ADBE Text Opacity") : null;
        if (opacity) opacity.setValue(opacityValue);
        var selectors = animator.property("ADBE Text Selectors");
        var selector = selectors ? selectors.addProperty("ADBE Text Selector") : null;
        this._kwvSetTextRangePercent(selector, startPercent, endPercent);
        return true;
    } catch (err) {
        return false;
    }
};

toolkit._kwvApplyExploderVisibilityRange = function(layer, textLength, startIndex, endIndex) {
    textLength = Math.max(1, parseInt(textLength, 10) || 1);
    var startPercent = Math.max(0, Math.min(100, (startIndex / textLength) * 100));
    var endPercent = Math.max(0, Math.min(100, (endIndex / textLength) * 100));
    this._kwvAddTextOpacityRange(layer, "KWV_HIDE_ALL", 0, 0, 100);
    this._kwvAddTextOpacityRange(layer, "KWV_SHOW_PART", 100, startPercent, endPercent);
};

toolkit._kwvSpreadExplodedTextLayers = function(comp, sourceLayer, newLayers) {
    if (!comp || !sourceLayer || !newLayers || newLayers.length < 2) return;
    try {
        var t = comp.time;
        var transform = sourceLayer.property("ADBE Transform Group");
        var posProp = transform ? transform.property("ADBE Position") : null;
        if (!posProp || posProp.isTimeVarying) return;
        var base = posProp.value;
        if (!base || base.length < 2) return;
        var sourceRect = sourceLayer.sourceRectAtTime(t, false);
        var widths = [];
        var total = 0;
        for (var i = 0; i < newLayers.length; i++) {
            this._kwvCenterExplodedTextAnchor(newLayers[i], t);
            var rect = newLayers[i].sourceRectAtTime(t, false);
            var width = Math.max(1, rect ? rect.width : 1);
            widths.push(width);
            total += width;
        }
        var fontSize = 48;
        try {
            var doc = sourceLayer.property("ADBE Text Properties").property("ADBE Text Document").value;
            if (doc && doc.fontSize) fontSize = doc.fontSize;
        } catch (fontErr) {}
        var gap = Math.max(8, Math.min(36, fontSize * 0.28));
        total += gap * (newLayers.length - 1);

        var cursor = -total / 2;
        for (var j = 0; j < newLayers.length; j++) {
            var layer = newLayers[j];
            var layerPos = layer.property("ADBE Transform Group").property("ADBE Position");
            if (!layerPos || layerPos.isTimeVarying) continue;
            var next = [];
            for (var k = 0; k < base.length; k++) next.push(base[k]);
            next[0] = base[0] + cursor + (widths[j] / 2);
            next[1] = base[1];
            layerPos.setValue(next);
            cursor += widths[j] + gap;
        }
    } catch (err) {}
};

toolkit._kwvOrderExplodedLayersBottomToTop = function(sourceLayer, newLayers) {
    if (!sourceLayer || !newLayers || newLayers.length < 2) return;
    try {
        for (var i = newLayers.length - 1; i >= 0; i--) {
            try { newLayers[i].moveBefore(sourceLayer); } catch (moveErr) {}
        }
    } catch (err) {}
};

toolkit._kwvCollapseExploderTimeline = function(comp, layers) {
    if (!comp || !layers || !layers.length) return;
    try {
        for (var i = 1; i <= comp.numLayers; i++) {
            try { comp.layer(i).selected = false; } catch (clearErr) {}
        }
        for (var j = 0; j < layers.length; j++) {
            try { layers[j].selected = true; } catch (selectErr) {}
        }
        try { app.executeCommand(2387); } catch (cmdErr) {}
        for (var k = 1; k <= comp.numLayers; k++) {
            try { comp.layer(k).selected = false; } catch (deselectErr) {}
        }
    } catch (err) {}
};

toolkit.explodeSelectedText = function(mode) {
    var comp = this.getComp();
    if (!(comp instanceof CompItem)) return "error::Open/select a composition first.";
    var selected = comp.selectedLayers || [];
    if (!selected.length) return "error::Select at least one text layer.";

    var targets = [];
    for (var i = 0; i < selected.length; i++) {
        try {
            if (selected[i] instanceof TextLayer) targets.push(selected[i]);
        } catch (typeErr) {}
    }
    if (!targets.length) return "error::Selected layer text layer nahi hai.";

    var isChars = String(mode || "") === "chars";
    var totalCreated = 0;
    app.beginUndoGroup(isChars ? "Text Exploder Characters" : "Text Exploder Words");
    try {
        for (var t = 0; t < targets.length; t++) {
            var sourceLayer = targets[t];
            var text = this._kwvGetTextLayerText(sourceLayer);
            var parts = this._kwvExploderParts(text, isChars ? "chars" : "words");
            if (parts.length < 1) continue;

            var wasLocked = false;
            try {
                wasLocked = sourceLayer.locked;
                sourceLayer.locked = false;
            } catch (lockErr) {}

            var created = [];
            for (var n = 0; n < parts.length; n++) {
                var copy = sourceLayer.duplicate();
                this._kwvApplyExploderVisibilityRange(copy, text.length, parts[n].start, parts[n].end);
                try { copy.name = this._kwvSafeExplodedLayerName(isChars ? "CHAR" : "WORD", parts[n].text, n); } catch (nameErr) {}
                try { copy.moveBefore(sourceLayer); } catch (moveErr) {}
                try { copy.selected = false; } catch (copySelectErr) {}
                created.push(copy);
                totalCreated++;
            }

            this._kwvOrderExplodedLayersBottomToTop(sourceLayer, created);
            try { sourceLayer.remove(); } catch (removeErr) {
                try { sourceLayer.enabled = false; } catch (hideErr) {}
            }
            this._kwvCollapseExploderTimeline(comp, created);
            try { sourceLayer.locked = wasLocked; } catch (restoreErr) {}
        }
    } catch (err) {
        return "error::Text exploder failed: " + err.toString();
    } finally {
        app.endUndoGroup();
    }
    if (totalCreated < 1) return "error::Text layer me split karne layak text nahi mila.";
    return "success::Created " + totalCreated + " text layer" + (totalCreated === 1 ? "." : "s.");
};

toolkit._kwvEffectKey = function(effect) {
    var matchName = "";
    var name = "";
    try { matchName = String(effect.matchName || ""); } catch (e1) {}
    try { name = String(effect.name || ""); } catch (e2) {}
    return matchName ? ("match::" + matchName) : ("name::" + name);
};

toolkit.scanCompEffects = function() {
    var comp = this.getComp();
    if (!(comp instanceof CompItem)) return "error::Open/select a composition first.";

    var groups = {};
    var order = [];
    for (var i = 1; i <= comp.numLayers; i++) {
        var layer = comp.layer(i);
        var effects = null;
        try { effects = layer.property("ADBE Effect Parade"); } catch (e1) { effects = null; }
        if (!effects || !effects.numProperties) continue;

        for (var j = 1; j <= effects.numProperties; j++) {
            var effect = null;
            try { effect = effects.property(j); } catch (e2) { effect = null; }
            if (!effect) continue;

            var key = this._kwvEffectKey(effect);
            if (!groups[key]) {
                var effectName = "";
                var matchName = "";
                try { effectName = String(effect.name || "Effect"); } catch (e3) { effectName = "Effect"; }
                try { matchName = String(effect.matchName || ""); } catch (e4) { matchName = ""; }
                groups[key] = {
                    key: key,
                    name: effectName,
                    matchName: matchName,
                    count: 0,
                    enabledCount: 0
                };
                order.push(key);
            }
            groups[key].count++;
            try { if (effect.enabled) groups[key].enabledCount++; } catch (e5) {}
        }
    }

    var effectsOut = [];
    for (var k = 0; k < order.length; k++) effectsOut.push(groups[order[k]]);
    effectsOut.sort(function(a, b) {
        var an = String(a.name || "").toLowerCase();
        var bn = String(b.name || "").toLowerCase();
        if (an < bn) return -1;
        if (an > bn) return 1;
        return 0;
    });
    return JSON.stringify({ compName: comp.name, effects: effectsOut });
};

toolkit.setCompEffectEnabled = function(effectKey, enabled) {
    var comp = this.getComp();
    if (!(comp instanceof CompItem)) return "error::Open/select a composition first.";

    var key = String(effectKey || "");
    if (!key) return "error::Effect key missing.";
    var nextEnabled = !!enabled;
    var changed = 0;
    var skipped = 0;

    app.beginUndoGroup(nextEnabled ? "Enable Comp Effects" : "Disable Comp Effects");
    try {
        for (var i = 1; i <= comp.numLayers; i++) {
            var layer = comp.layer(i);
            var effects = null;
            try { effects = layer.property("ADBE Effect Parade"); } catch (e1) { effects = null; }
            if (!effects || !effects.numProperties) continue;

            var wasLocked = false;
            try { wasLocked = !!layer.locked; } catch (lockReadErr) { wasLocked = false; }
            if (wasLocked) {
                try { layer.locked = false; } catch (unlockErr) {}
            }
            try {
                for (var j = 1; j <= effects.numProperties; j++) {
                    var effect = null;
                    try { effect = effects.property(j); } catch (e2) { effect = null; }
                    if (!effect) continue;
                    if (this._kwvEffectKey(effect) !== key) continue;
                    try {
                        effect.enabled = nextEnabled;
                        changed++;
                    } catch (setErr) {
                        skipped++;
                    }
                }
            } finally {
                if (wasLocked) {
                    try { layer.locked = true; } catch (relockErr) {}
                }
            }
        }
    } catch (err) {
        return "error::Could not update effects: " + err.toString();
    } finally {
        app.endUndoGroup();
    }

    if (changed < 1) return "error::No matching effect instances found.";
    return "success::Updated " + changed + " effect instance" + (changed === 1 ? "" : "s") + (skipped ? " (" + skipped + " skipped)." : ".");
};

toolkit.unprecompStable = function() {
    var comp = this.getComp();
    if (!comp) {
        alert("Open a composition first!");
        return;
    }
    var selectedLayers = comp.selectedLayers;
    if (!selectedLayers || selectedLayers.length !== 1) {
        alert("Select exactly ONE precomp!");
        return;
    }
    var precompLayer = selectedLayers[0];
    if (!precompLayer.source || !(precompLayer.source instanceof CompItem)) {
        alert("Not a precomp!");
        return;
    }

    app.beginUndoGroup("Smart Decomp");
    try {
        var self = this;
        var sourceComp = precompLayer.source;
        var precompInPoint = precompLayer.inPoint;
        var precompOutPoint = precompLayer.outPoint;
        var sourceDisplayStart = 0;
        try { sourceDisplayStart = sourceComp.displayStartTime || 0; } catch (displayStartErr) {}
        var sourceAnchorTime = sourceDisplayStart;
        var targetAnchorTime = precompInPoint;
        try {
            var minSourceIn = null;
            for (var anchorIndex = 1; anchorIndex <= sourceComp.numLayers; anchorIndex++) {
                var anchorLayer = sourceComp.layer(anchorIndex);
                try {
                    if (anchorLayer.nullLayer) continue;
                } catch (anchorNullErr) {}
                if (minSourceIn === null || anchorLayer.inPoint < minSourceIn) minSourceIn = anchorLayer.inPoint;
            }
            if (minSourceIn !== null) sourceAnchorTime = minSourceIn;
        } catch (anchorErr) {}
        try {
            if (comp.time >= precompInPoint && comp.time <= precompOutPoint) {
                targetAnchorTime = comp.time;
            }
        } catch (targetAnchorErr) {}
        var frameDuration = comp.frameDuration || 0.001;
        var copiedCount = 0;
        var copiedLayers = [];

        function mapNestedTime(timeValue) {
            var stretch = 1;
            try { stretch = (precompLayer.stretch ? precompLayer.stretch : 100) / 100; } catch (stretchErr) {}
            return targetAnchorTime + (((timeValue || 0) - sourceAnchorTime) * stretch);
        }

        function clampToPrecompVisibleRange(timeValue) {
            return Math.min(precompOutPoint, Math.max(precompInPoint, timeValue));
        }

        function valueClose(a, b, epsilon) {
            epsilon = epsilon || 0.01;
            try {
                if (a instanceof Array || b instanceof Array) {
                    if (!(a instanceof Array) || !(b instanceof Array) || a.length !== b.length) return false;
                    for (var vi = 0; vi < a.length; vi++) {
                        if (Math.abs(Number(a[vi]) - Number(b[vi])) > epsilon) return false;
                    }
                    return true;
                }
                return Math.abs(Number(a) - Number(b)) <= epsilon;
            } catch (closeErr) {
                return false;
            }
        }

        function propHasAnimation(prop) {
            try {
                return !!(prop && ((prop.numKeys && prop.numKeys > 0) || prop.expressionEnabled));
            } catch (animErr) {
                return false;
            }
        }

        function shouldUseTransformCarrier() {
            try {
                if (precompLayer.parent) return true;
                if (precompLayer.threeDLayer) return true;
                var tr = precompLayer.property("ADBE Transform Group");
                if (!tr) return false;
                var anchor = tr.property("ADBE Anchor Point");
                var position = tr.property("ADBE Position");
                var scale = tr.property("ADBE Scale");
                var rotation = tr.property("ADBE Rotate Z");
                var opacity = tr.property("ADBE Opacity");
                if (propHasAnimation(anchor) || propHasAnimation(position) || propHasAnimation(scale) || propHasAnimation(rotation) || propHasAnimation(opacity)) return true;

                var defaultAnchor = [sourceComp.width / 2, sourceComp.height / 2];
                var defaultPosition = [comp.width / 2, comp.height / 2];
                var sameSizedDefaultPosition = [sourceComp.width / 2, sourceComp.height / 2];
                var positionIsIdentity = valueClose(position.value, defaultPosition, 0.01) || valueClose(position.value, sameSizedDefaultPosition, 0.01);
                return !(
                    valueClose(anchor.value, defaultAnchor, 0.01) &&
                    positionIsIdentity &&
                    valueClose(scale.value, [100, 100], 0.01) &&
                    valueClose(rotation.value, 0, 0.001) &&
                    valueClose(opacity.value, 100, 0.01)
                );
            } catch (carrierCheckErr) {
                return true;
            }
        }

        function copyPropertyState(srcProp, dstProp) {
            try {
                if (!srcProp || !dstProp) return;
                if (srcProp.numKeys && srcProp.numKeys > 0 && dstProp.canVaryOverTime) {
                    while (dstProp.numKeys && dstProp.numKeys > 0) {
                        try { dstProp.removeKey(1); } catch (removeKeyErr) { break; }
                    }
                    for (var k = 1; k <= srcProp.numKeys; k++) {
                        var t = srcProp.keyTime(k);
                        try { dstProp.setValueAtTime(t, srcProp.keyValue(k)); } catch (setKeyErr) {}
                        try { dstProp.setInterpolationTypeAtKey(k, srcProp.keyInInterpolationType(k), srcProp.keyOutInterpolationType(k)); } catch (interpErr) {}
                        try { dstProp.setTemporalEaseAtKey(k, srcProp.keyInTemporalEase(k), srcProp.keyOutTemporalEase(k)); } catch (easeErr) {}
                        try { dstProp.setTemporalContinuousAtKey(k, srcProp.keyTemporalContinuous(k)); } catch (tempContErr) {}
                        try { dstProp.setTemporalAutoBezierAtKey(k, srcProp.keyTemporalAutoBezier(k)); } catch (tempAutoErr) {}
                        try {
                            if (srcProp.isSpatial && dstProp.isSpatial) {
                                dstProp.setSpatialTangentsAtKey(k, srcProp.keyInSpatialTangent(k), srcProp.keyOutSpatialTangent(k));
                                dstProp.setSpatialContinuousAtKey(k, srcProp.keySpatialContinuous(k));
                                dstProp.setSpatialAutoBezierAtKey(k, srcProp.keySpatialAutoBezier(k));
                                if (dstProp.setRovingAtKey) dstProp.setRovingAtKey(k, srcProp.keyRoving(k));
                            }
                        } catch (spatialErr) {}
                    }
                } else if (!dstProp.isTimeVarying) {
                    try { dstProp.setValue(srcProp.value); } catch (staticErr) {}
                } else {
                    try { dstProp.setValue(srcProp.value); } catch (varyingStaticErr) {}
                }
                try {
                    if (srcProp.expressionEnabled && srcProp.expression) {
                        dstProp.expression = srcProp.expression;
                        dstProp.expressionEnabled = true;
                    }
                } catch (exprErr) {}
            } catch (copyPropErr) {}
        }

        function copyTransformValue(srcTransform, dstTransform, matchName) {
            try {
                copyPropertyState(srcTransform.property(matchName), dstTransform.property(matchName));
            } catch (copyTransformErr) {}
        }

        function createPrecompTransformCarrier() {
            var carrier = comp.layers.addNull();
            carrier.name = "[Unprecomp Transform] " + precompLayer.name;
            carrier.startTime = precompLayer.startTime;
            carrier.inPoint = precompInPoint;
            carrier.outPoint = precompOutPoint;
            try { carrier.guideLayer = true; } catch (guideErr) {}
            try { carrier.shy = true; } catch (shyErr) {}
            try { carrier.label = precompLayer.label; } catch (labelErr) {}
            try { carrier.moveBefore(precompLayer); } catch (carrierMoveErr) {}

            try {
                if (precompLayer.threeDLayer) carrier.threeDLayer = true;
            } catch (threeDErr) {}

            var srcTransform = precompLayer.property("ADBE Transform Group");
            var dstTransform = carrier.property("ADBE Transform Group");
            copyTransformValue(srcTransform, dstTransform, "ADBE Anchor Point");
            copyTransformValue(srcTransform, dstTransform, "ADBE Position");
            copyTransformValue(srcTransform, dstTransform, "ADBE Scale");
            copyTransformValue(srcTransform, dstTransform, "ADBE Rotate Z");
            copyTransformValue(srcTransform, dstTransform, "ADBE Opacity");
            copyTransformValue(srcTransform, dstTransform, "ADBE Orientation");
            copyTransformValue(srcTransform, dstTransform, "ADBE Rotate X");
            copyTransformValue(srcTransform, dstTransform, "ADBE Rotate Y");
            return carrier;
        }

        var transformCarrier = shouldUseTransformCarrier() ? createPrecompTransformCarrier() : null;

        for (var i = 1; i <= sourceComp.numLayers; i++) {
            var srcLayer = sourceComp.layer(i);
            try {
                if (srcLayer.nullLayer) continue;
            } catch (skipNullErr) {}
            var wasLocked = false;
            try { wasLocked = !!srcLayer.locked; srcLayer.locked = false; } catch (lockErr) {}
            try {
                var mappedStart = mapNestedTime(srcLayer.startTime);
                var mappedInA = mapNestedTime(srcLayer.inPoint);
                var mappedOutA = mapNestedTime(srcLayer.outPoint);
                var mappedIn = clampToPrecompVisibleRange(Math.min(mappedInA, mappedOutA));
                var mappedOut = clampToPrecompVisibleRange(Math.max(mappedInA, mappedOutA));

                if (mappedOut <= mappedIn + frameDuration) continue;

                srcLayer.copyToComp(comp);
                var newLayer = comp.layer(1);
                if (!newLayer) continue;

                try { newLayer.startTime = mappedStart; } catch (startErr) {}
                try { newLayer.inPoint = mappedIn; } catch (inErr) {}
                try { newLayer.outPoint = mappedOut; } catch (outErr) {}
                try { newLayer.moveBefore(precompLayer); } catch (moveErr) {}
                if (transformCarrier) {
                    try {
                        newLayer.parent = transformCarrier;
                    } catch (parentErr) {}
                }
                copiedLayers.push(newLayer);
                copiedCount++;
            } catch (copyErr) {
            } finally {
                try { srcLayer.locked = wasLocked; } catch (restoreLockErr) {}
            }
        }

        if (copiedCount > 0) {
            if (transformCarrier) {
                for (var bakeIndex = 0; bakeIndex < copiedLayers.length; bakeIndex++) {
                    try {
                        if (copiedLayers[bakeIndex] && copiedLayers[bakeIndex].parent === transformCarrier && copiedLayers[bakeIndex].setParentWithJump) {
                            copiedLayers[bakeIndex].setParentWithJump(null);
                        } else if (copiedLayers[bakeIndex] && copiedLayers[bakeIndex].parent === transformCarrier) {
                            copiedLayers[bakeIndex].parent = null;
                        }
                    } catch (bakeErr) {}
                }
                try { transformCarrier.remove(); } catch (removeBakedCarrierErr) {}
            }
            precompLayer.remove();
        } else {
            if (transformCarrier) {
                try { transformCarrier.remove(); } catch (removeCarrierErr) {}
            }
            alert("No layers could be copied from this precomp.");
        }
    } catch (e) {
        alert("Decomp Error:\n" + e.toString());
    } finally {
        app.endUndoGroup();
    }
};

